import React from 'react';

interface SubmissionOverlayProps {
    status: 'idle' | 'submitting' | 'success' | 'offline_saved';
    aiSummary?: string | null;
    onClose?: () => void;
    onViewReport?: () => void;
}

const SubmissionOverlay: React.FC<SubmissionOverlayProps> = ({ status, aiSummary, onClose, onViewReport }) => {
    if (status === 'idle') return null;

    const isProcessing = status === 'submitting' || (status === 'success' && !aiSummary);

    return (
        <div className="fixed inset-0 z-[100] flex items-center justify-center">
            {/* Backdrop with Blur */}
            <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-md transition-all duration-300"></div>

            {/* Content Card */}
            <div className={`relative bg-white rounded-3xl shadow-2xl p-8 w-full mx-4 text-center transform transition-all duration-300 scale-100 animate-fadeIn border border-white/20
                ${aiSummary ? 'max-w-2xl' : 'max-w-sm'}
            `}>

                {status === 'submitting' && (
                    <div className="flex flex-col items-center gap-4 py-4">
                        <div className="relative">
                            <div className="w-16 h-16 border-4 border-blue-100 border-t-blue-600 rounded-full animate-spin"></div>
                            <div className="absolute inset-0 flex items-center justify-center">
                                <svg className="w-6 h-6 text-blue-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"></path></svg>
                            </div>
                        </div>
                        <div>
                            <h3 className="text-lg font-bold text-gray-900">Uploading Inspection</h3>
                            <p className="text-sm text-gray-500 mt-1">Syncing with Fleet Database...</p>
