                        </div>

                        <div className="w-full text-left bg-slate-50 rounded-2xl border border-slate-100 overflow-hidden">
                            <div className="bg-indigo-600 px-6 py-3 flex justify-between items-center">
                                <h4 className="text-white font-bold text-xs uppercase tracking-widest flex items-center gap-2">
                                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" /></svg>
                                    AI Safety Manager Review
                                </h4>
                                <span className="text-[10px] font-black bg-white/20 text-white px-2 py-0.5 rounded-full uppercase">Compliance Engine</span>
                            </div>
                            <div className="p-6">
                                <div className="prose prose-sm max-h-[300px] overflow-y-auto pr-2 scrollbar-hide">
                                    <p className="text-slate-700 font-medium whitespace-pre-wrap leading-relaxed text-sm">
                                        {aiSummary}
                                    </p>
                                </div>
                            </div>
                        </div>

                        <div className="flex flex-col sm:flex-row gap-3 w-full">
                            <button 
                                onClick={onViewReport}
                                className="flex-1 py-4 bg-white border border-slate-200 text-slate-700 font-bold rounded-xl shadow-sm hover:bg-slate-50 transition-all flex items-center justify-center gap-2 text-xs uppercase tracking-widest"
                            >
