            {isSuperAdmin && (
                <NavItem id="maintenance" label="Security" icon={<svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2"><path d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z"/></svg>} />
            )}
          </div>
        </div>

        {/* Footer */}
        <div className="border-t border-white/5 p-4 shrink-0 overflow-hidden">
            <button 
              id="support"
              onClick={() => { onSelectModule('support'); onClose(); }}
              className={`w-full flex items-center gap-4 px-3 py-4 rounded-xl transition-all duration-300
                ${activeModule === 'support' ? 'bg-indigo-600 text-white' : 'text-slate-400 hover:text-white hover:bg-white/5'}
              `}
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2"><path d="M18.364 5.636l-3.536 3.536m0 5.656l3.536 3.536M9.172 9.172L5.636 5.636m3.536 9.192l-3.536 3.536M21 12a9 9 0 11-18 0 9 9 0 0118 0zm-5 0a4 4 0 11-8 0 4 4 0 018 0z"/></svg>
              <span className={`text-xs font-bold uppercase tracking-widest transition-opacity ${!isOpen && 'opacity-0'}`}>
                Support
              </span>
            </button>
            <button 
                onClick={onLogout}
                className="w-full flex items-center gap-4 px-3 py-4 text-rose-400 hover:text-rose-300 hover:bg-rose-500/10 rounded-xl transition-all mt-1"
            >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2"><path d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H5a3 3-0 01-3-3V7a3 3-0 013-3h4a3 3-0 013 3v1"/></svg>
                <span className={`text-xs font-bold uppercase tracking-widest transition-opacity ${!isOpen && 'opacity-0'}`}>
                    Log Out
                </span>
            </button>
        </div>
      </aside>
    </>
  );
};

