                                            <p className="font-black text-base uppercase tracking-tight">{reg}</p>
                                            <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Multiple Safety Alerts</p>
                                        </div>
                                    </div>
                                    <div className="text-right">
                                        <p className="text-xl font-black text-rose-400 leading-none">{count}</p>
                                        <p className="text-[8px] font-black text-slate-500 uppercase mt-1">Issues</p>
                                    </div>
