            {/* AI Insights Area */}
            <div className="space-y-6">
                <div className="bg-gradient-to-r from-indigo-600 to-blue-700 p-8 rounded-[2rem] shadow-xl text-white flex flex-col md:flex-row items-center justify-between gap-6 relative overflow-hidden">
                    <div className="absolute top-0 right-0 w-32 h-32 bg-white/5 rounded-full -mr-10 -mt-10 blur-2xl"></div>
                    <div className="flex items-center gap-4 relative z-10">
                        <div className="w-12 h-12 bg-white/20 rounded-2xl flex items-center justify-center backdrop-blur-md border border-white/10">
                            <svg className={`w-6 h-6 text-white ${isGenerating ? 'animate-pulse' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 10V3L4 14h7v7l9-11h-7z" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
                        </div>
                        <div>
                            <h4 className="font-black text-lg uppercase tracking-tight leading-none">Intelligence Engine</h4>
                            <p className="text-[10px] font-bold text-indigo-200 uppercase tracking-widest mt-1">Generative Trends Analysis</p>
                        </div>
                    </div>
                    <button 
                        onClick={handleGenerateSummary}
                        disabled={isGenerating}
                        className="relative z-10 px-8 py-3 bg-white text-indigo-600 rounded-xl font-black text-[11px] uppercase tracking-widest shadow-lg hover:shadow-white/20 transition-all active:scale-95 disabled:bg-indigo-100 disabled:text-indigo-300 flex items-center gap-2"
                    >
                        {isGenerating ? (
                            <>
                                <svg className="animate-spin h-3 w-3" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                                Analyzing...
                            </>
                        ) : 'Generate Executive Summary'}
                    </button>
                </div>

                {aiSummary && (
                    <div className="bg-white p-10 rounded-[2.5rem] border-2 border-indigo-50 shadow-2xl animate-fadeIn relative">
                        <div className="absolute top-6 right-8">
                            <span className="text-[8px] font-black bg-indigo-100 text-indigo-600 px-2 py-1 rounded uppercase tracking-widest">AI Generated</span>
                        </div>
