            const highRiskVehicles = metrics.topFailing.length > 0 
                ? `Immediate priority should be given to high-risk assets: ${metrics.topFailing.slice(0, 2).map(([reg]) => reg).join(' and ')}.`
                : "No single asset shows a chronic pattern of failure.";

            const summary = `EXECUTIVE BRIEFING:
${healthStatus} Out of ${metrics.total} audits, ${metrics.goodCount} were satisfactory. Currently, ${metrics.criticalCount} assets are grounded for critical safety violations.

RECOMMENDED STRATEGY:
1. ${highRiskVehicles}
2. Conduct a deep-dive technical review on the ${metrics.warningCount} units currently marked with 'Needs Attention' to prevent escalation to critical failure.
3. Review driver pre-trip checklists to ensure early detection of common faults before formal audits.`;

            setAnalysisSummary(summary);
            setIsGenerating(false);
        }, 600);
    };

    if (isLoading) {
        return (
            <div className="flex flex-col items-center justify-center py-24 gap-4">
                <div className="w-12 h-12 border-4 border-slate-100 border-t-indigo-600 rounded-full animate-spin"></div>
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Aggregating Fleet Intelligence...</p>
            </div>
        );
    }

    if (!metrics) {
        return (
            <div className="py-24 text-center">
                <p className="text-slate-400 font-medium text-sm italic">Insufficient data to generate analytics report.</p>
            </div>
        );
    }

    return (
        <div className="max-w-6xl mx-auto space-y-10 animate-fadeIn font-sans pb-24">
            <div className="flex justify-between items-end px-2">
                <div>
                    <h2 className="text-3xl font-black text-slate-900 uppercase tracking-tight leading-none">Fleet Insights</h2>
                    <p className="text-slate-400 text-[10px] font-bold uppercase tracking-[0.3em] mt-3">Compliance & Risk Performance</p>
                </div>
                <div className="text-right">
                    <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest">Calculated Engine: Native</span>
                </div>
            </div>

            {/* KPI Row */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm">
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Total Audits</p>
                    <h3 className="text-4xl font-black text-slate-900">{metrics.total}</h3>
                    <div className="h-1 bg-slate-100 rounded-full mt-6 overflow-hidden">
                        <div className="h-full bg-slate-400 w-full"></div>
                    </div>
                </div>
                <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm">
                    <p className="text-[10px] font-black text-emerald-500 uppercase tracking-widest mb-4">Pass Rate</p>
                    <h3 className="text-4xl font-black text-emerald-600">{metrics.passRate}%</h3>
                    <div className="h-1 bg-emerald-50 rounded-full mt-6 overflow-hidden">
                        <div className="h-full bg-emerald-500" style={{ width: `${metrics.passRate}%` }}></div>
                    </div>
                </div>
                <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm">
                    <p className="text-[10px] font-black text-amber-500 uppercase tracking-widest mb-4">Warnings</p>
                    <h3 className="text-4xl font-black text-amber-600">{metrics.warningCount}</h3>
                    <div className="h-1 bg-amber-50 rounded-full mt-6 overflow-hidden">
                        <div className="h-full bg-amber-500" style={{ width: `${(metrics.warningCount / metrics.total) * 100}%` }}></div>
                    </div>
                </div>
                <div className="bg-rose-50 p-6 rounded-3xl border border-rose-100 shadow-sm">
                    <p className="text-[10px] font-black text-rose-500 uppercase tracking-widest mb-4">Critical Failures</p>
                    <h3 className="text-4xl font-black text-rose-600">{metrics.criticalCount}</h3>
                    <div className="h-1 bg-rose-100 rounded-full mt-6 overflow-hidden">
                        <div className="h-full bg-rose-500" style={{ width: `${(metrics.criticalCount / metrics.total) * 100}%` }}></div>
                    </div>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                {/* Risk Distribution Card */}
                <div className="bg-white p-10 rounded-[2.5rem] border border-slate-100 shadow-sm">
                    <h4 className="text-sm font-black text-slate-800 uppercase tracking-widest mb-8 flex items-center gap-2">
                        <div className="w-2 h-2 rounded-full bg-indigo-500"></div>
                        Asset Condition Profile
                    </h4>
                    <div className="space-y-6">
                        {[
                            { label: 'Exemplary (5/5)', count: historyList.filter(h => Number(h.rate) === 5).length, color: 'bg-emerald-600' },
                            { label: 'Good (4/5)', count: historyList.filter(h => Number(h.rate) === 4).length, color: 'bg-emerald-400' },
                            { label: 'Serviceable (3/5)', count: metrics.warningCount, color: 'bg-amber-400' },
                            { label: 'Immediate Action (1-2/5)', count: metrics.criticalCount, color: 'bg-rose-500' },
                        ].map((row, idx) => {
                            const pct = ((row.count / metrics.total) * 100).toFixed(0);
                            return (
                                <div key={idx} className="space-y-2">
                                    <div className="flex justify-between text-[11px] font-bold text-slate-500 uppercase tracking-tighter">
                                        <span>{row.label}</span>
                                        <span className="text-slate-900">{row.count} Units ({pct}%)</span>
                                    </div>
                                    <div className="h-3 bg-slate-50 rounded-lg overflow-hidden border border-slate-100">
                                        <div className={`h-full ${row.color} transition-all duration-1000`} style={{ width: `${pct}%` }}></div>
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                </div>

                {/* High-Risk Assets Card */}
                <div className="bg-slate-900 p-10 rounded-[2.5rem] text-white shadow-2xl relative overflow-hidden">
                    <div className="absolute top-0 right-0 w-64 h-64 bg-indigo-500/10 rounded-full -mr-20 -mt-20 blur-3xl"></div>
                    <h4 className="text-sm font-black text-indigo-300 uppercase tracking-widest mb-8 relative z-10">High-Risk Asset Focus</h4>

                    {metrics.topFailing.length > 0 ? (
                        <div className="space-y-4 relative z-10">
                            {metrics.topFailing.map(([reg, count], idx) => (
                                <div key={idx} className="flex items-center justify-between p-4 bg-white/5 rounded-2xl border border-white/5 hover:bg-white/10 transition-colors">
                                    <div className="flex items-center gap-4">
                                        <span className="text-lg font-black text-indigo-400 opacity-50">#{idx + 1}</span>
                                        <div>
                                            <p className="font-black text-base uppercase tracking-tight">{reg}</p>
                                            <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Multiple Safety Alerts</p>
                                        </div>
                                    </div>
                                    <div className="text-right">
                                        <p className="text-xl font-black text-rose-400 leading-none">{count}</p>
                                        <p className="text-[8px] font-black text-slate-500 uppercase mt-1">Issues</p>
                                    </div>
                                </div>
                            ))}
                        </div>
                    ) : (
                        <div className="h-40 flex items-center justify-center relative z-10">
                            <p className="text-slate-500 italic text-sm">No significant risk patterns detected.</p>
                        </div>
                    )}
                </div>
            </div>

            {/* Manual Analytics Area */}
            <div className="space-y-6">
                <div className="bg-gradient-to-r from-slate-800 to-slate-900 p-8 rounded-[2rem] shadow-xl text-white flex flex-col md:flex-row items-center justify-between gap-6 relative overflow-hidden">
                    <div className="absolute top-0 right-0 w-32 h-32 bg-white/5 rounded-full -mr-10 -mt-10 blur-2xl"></div>
                    <div className="flex items-center gap-4 relative z-10">
                        <div className="w-12 h-12 bg-white/10 rounded-2xl flex items-center justify-center backdrop-blur-md border border-white/5">
                            <svg className={`w-6 h-6 text-white ${isGenerating ? 'animate-pulse' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M9 17v-2m3 2v-4m3 4v-6m2 10H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
                        </div>
                        <div>
                            <h4 className="font-black text-lg uppercase tracking-tight leading-none">Logic Engine</h4>
                            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1">Instant Fleet Evaluation</p>
                        </div>
                    </div>
                    <button 
                        onClick={handleGenerateSummary}
                        disabled={isGenerating}
                        className="relative z-10 px-8 py-3 bg-white text-slate-900 rounded-xl font-black text-[11px] uppercase tracking-widest shadow-lg hover:bg-slate-50 transition-all active:scale-95 disabled:bg-slate-100 disabled:text-slate-300 flex items-center gap-2"
                    >
                        {isGenerating ? (
                            <>
                                <svg className="animate-spin h-3 w-3" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                                Calculating...
                            </>
                        ) : 'Generate Executive Summary'}
                    </button>
                </div>

                {analysisSummary && (
                    <div className="bg-white p-10 rounded-[2.5rem] border border-slate-100 shadow-2xl animate-fadeIn relative">
                        <div className="absolute top-6 right-8">
                            <span className="text-[8px] font-black bg-slate-100 text-slate-500 px-2 py-1 rounded uppercase tracking-widest">Logic-Driven Report</span>
                        </div>
                        <h5 className="text-sm font-black text-slate-400 uppercase tracking-[0.2em] mb-6">Management Briefing</h5>
                        <div className="prose prose-slate max-w-none">
                            <p className="text-slate-700 font-medium whitespace-pre-wrap leading-relaxed text-sm">
                                {analysisSummary}
                            </p>
                        </div>
                        <div className="mt-8 pt-6 border-t border-slate-50 flex justify-end">
                            <button 
                                onClick={() => setAnalysisSummary(null)}
                                className="text-[10px] font-bold text-slate-300 hover:text-slate-500 uppercase tracking-widest transition-colors"
                            >
                                Clear Analysis
                            </button>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

