import React, { useMemo, useState } from 'react';
import { InspectionData } from '../types';

interface AnalyticsDashboardProps {
    historyList: InspectionData[];
    isLoading: boolean;
}

const AnalyticsDashboard: React.FC<AnalyticsDashboardProps> = ({ historyList, isLoading }) => {
    const [isGenerating, setIsGenerating] = useState(false);
    const [analysisSummary, setAnalysisSummary] = useState<string | null>(null);

    const metrics = useMemo(() => {
        if (!historyList.length) return null;

        const total = historyList.length;
        const criticalCount = historyList.filter(h => Number(h.rate) <= 2).length;
        const warningCount = historyList.filter(h => Number(h.rate) === 3).length;
        const goodCount = historyList.filter(h => Number(h.rate) >= 4).length;

        const passRateNum = (goodCount / total) * 100;
        const passRate = passRateNum.toFixed(1);

        const truckFailures: Record<string, number> = {};
        const driverScores: Record<string, number> = {};

        // Intelligent Forecaster Tracking
        const truckTracking: Record<string, {
            minOdo: number, maxOdo: number, minTime: number, maxTime: number, lastRate: number
        }> = {};

        historyList.forEach(h => {
            const rate = Number(h.rate);
            const odo = Number(h.odometer);
            const time = new Date(h.timestamp).getTime();

            // 1. Failure tracking
            if (rate <= 3) {
                truckFailures[h.truckNo] = (truckFailures[h.truckNo] || 0) + 1;
            }

            // 2. Intelligence Aggregator for Forecaster
            if (odo && !isNaN(time)) {
                if (!truckTracking[h.truckNo]) {
                    truckTracking[h.truckNo] = { minOdo: odo, maxOdo: odo, minTime: time, maxTime: time, lastRate: rate };
                } else {
                    if (odo < truckTracking[h.truckNo].minOdo) {
                        truckTracking[h.truckNo].minOdo = odo;
                        truckTracking[h.truckNo].minTime = time;
                    }
                    if (time > truckTracking[h.truckNo].maxTime) {
                        truckTracking[h.truckNo].maxOdo = odo;
                        truckTracking[h.truckNo].maxTime = time;
                        truckTracking[h.truckNo].lastRate = rate;
                    }
                }
            }

            // 3. Leaderboard Scoring
            if (h.driverName) {
                const score = rate === 5 ? 10 : rate === 4 ? 5 : rate === 3 ? -5 : -20;
                driverScores[h.driverName] = (driverScores[h.driverName] || 0) + score;
            }
        });

        const topFailing = Object.entries(truckFailures)
            .sort(([, a], [, b]) => b - a)
            .slice(0, 5);

        const leaderboard = Object.entries(driverScores)
            .sort(([, a], [, b]) => b - a)
            .slice(0, 3);

        // 4. Predictive Maintenance Forecaster
        const SERVICE_INTERVAL = 10000; // 10,000km cycle
        const serviceAlerts = Object.entries(truckTracking).map(([truck, data]) => {
            const distanceRecorded = data.maxOdo - data.minOdo;
            const timeDiffDays = (data.maxTime - data.minTime) / (1000 * 60 * 60 * 24);
            const avgDailyKm = timeDiffDays > 0 ? (distanceRecorded / timeDiffDays) : 0;

            // Calculate current cycle progress
            const cycleKm = data.maxOdo % SERVICE_INTERVAL;
            const progress = (cycleKm / SERVICE_INTERVAL) * 100;
            const remainingKm = SERVICE_INTERVAL - cycleKm;

            // Predict days left
            const daysRemaining = avgDailyKm > 0 ? Math.round(remainingKm / avgDailyKm) : null;

            return {
                truck,
                progress: Math.min(100, Math.max(0, progress)),
                avgDailyKm: avgDailyKm.toFixed(1),
                daysRemaining,
                remainingKm,
                lastRate: data.lastRate,
                isUrgent: progress > 85 || data.lastRate <= 2
            };
        }).sort((a, b) => b.progress - a.progress).slice(0, 8);

        // 5. Condition Distribution
        const conditionDistribution = [
            { label: 'Exemplary (5/5)', count: historyList.filter(h => Number(h.rate) === 5).length, color: 'bg-emerald-600' },
            { label: 'Good (4/5)', count: historyList.filter(h => Number(h.rate) === 4).length, color: 'bg-emerald-400' },
            { label: 'Serviceable (3/5)', count: warningCount, color: 'bg-amber-400' },
            { label: 'Immediate Action (1-2/5)', count: criticalCount, color: 'bg-rose-500' },
        ];

        return { 
            total, criticalCount, warningCount, goodCount, passRate, passRateNum, 
            topFailing, serviceAlerts, leaderboard, conditionDistribution 
        };
    }, [historyList]);

    const handleGenerateSummary = () => {
        if (!metrics) return;
        setIsGenerating(true);
        setTimeout(() => {
            const pRate = metrics.passRateNum;
            let healthStatus = "";
            if (pRate >= 90) healthStatus = "The fleet is operating at peak safety compliance.";
            else if (pRate >= 75) healthStatus = "Overall fleet health is stable, though minor maintenance trends are emerging.";
            else healthStatus = "CRITICAL: The fleet safety rating has fallen below acceptable thresholds.";

            const urgentCount = metrics.serviceAlerts.filter(s => s.isUrgent).length;
            const forecastText = urgentCount > 0
                ? `Predictive analysis identifies ${urgentCount} assets requiring immediate service scheduling based on duty cycle and condition.`
                : "Operational duty cycles are currently within safe preventative windows.";

