            if (settingsRows && Array.isArray(settingsRows) && settingsRows.length > 1) {
                const latestConfig = settingsRows[1]; 
                if (latestConfig && latestConfig.length >= 8) {
                    const rawMaintenanceVal = String(latestConfig[7]).toUpperCase().trim();
                    const isMaintActive = rawMaintenanceVal === 'TRUE';

                    const remoteSettings: SystemSettings = {
                        companyName: latestConfig[0] || 'SafetyCheck Pro',
                        managerEmail: latestConfig[1] || '',
                        companyLogo: (latestConfig[4] && String(latestConfig[4]).length > 100) ? latestConfig[4] : undefined,
                        mobileApkLink: latestConfig[5] || '', 
                        webAppUrl: latestConfig[6] || '',
                        maintenanceMode: isMaintActive,
                        maintenanceMessage: latestConfig[8] || 'System under scheduled maintenance.'
                    };

                    setSettings(prev => {
                        const hasChanged = JSON.stringify(prev) !== JSON.stringify(remoteSettings);
                        if (hasChanged) {
                            localStorage.setItem('safetyCheck_settings', JSON.stringify(remoteSettings));
                            return remoteSettings;
                        }
                        return prev;
                    });
                }
            }
        } catch (error) {
            // Quiet fail for network
        } finally {
            isFetchingRef.current = false;
        }
    };

    const handleSaveSettings = async () => {
        setIsSavingSettings(true);
        isWritingRef.current = true;
        try {
            localStorage.setItem('safetyCheck_settings', JSON.stringify(settings));
            localStorage.setItem('safetyCheck_scriptUrl', appScriptUrl);

            if (appScriptUrl && appScriptUrl.startsWith('https') && navigator.onLine) {
                 await fetch(appScriptUrl, {
                    method: 'POST',
                    body: JSON.stringify({
                        action: 'update_settings',
                        ...settings
                    }),
                    mode: 'no-cors' 
                });
            }
        } catch (error) {
            console.error("Save Settings Failed", error);
        } finally {
            setTimeout(() => {
                setIsSavingSettings(false);
                isWritingRef.current = false;
            }, 800);
        }
    };

    return { 
        settings, 
        setSettings, 
        appScriptUrl, 
        setAppScriptUrl, 
        isSavingSettings, 
        handleSaveSettings,
        fetchSystemSettings
    };
};

import { GoogleGenAI } from "@google/genai";
import { InspectionData, InspectionStatus } from "../types";
import { INSPECTION_ITEMS } from "../constants";

export const analyzeInspection = async (data: InspectionData): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const failedItems = INSPECTION_ITEMS.filter(item => 
      data[item.id] === InspectionStatus.BAD
    );
    const attentionItems = INSPECTION_ITEMS.filter(item => 
      data[item.id] === InspectionStatus.ATTENTION
    );

    let prompt = `You are a Senior Fleet Safety Manager. Review the following truck inspection report.\n`;
    prompt += `Truck No: ${data.truckNo}, Trailer: ${data.trailerNo}, Odometer: ${data.odometer}\n`;

    prompt += `\nBAD / FAILED ITEMS (${failedItems.length}):\n`;
    if (failedItems.length === 0) {
      prompt += "None.\n";
    } else {
      failedItems.forEach(item => {
        prompt += `- ${item.label} (Status: Critical Failure)\n`;
      });
    }

    prompt += `\nITEMS NEEDING ATTENTION (${attentionItems.length}):\n`;
    if (attentionItems.length === 0) {
      prompt += "None.\n";
    } else {
      attentionItems.forEach(item => {
        prompt += `- ${item.label} (Status: Needs Attention)\n`;
      });
    }

    prompt += `\nREMARKS from Inspector: ${data.remarks || "No remarks provided."}\n`;
    prompt += `\nOverall Rating given by inspector: ${data.rate}/5\n`;

    prompt += `\nTask:\n`;
    prompt += `1. Summarize the condition of the vehicle in 2 sentences.\n`;
    prompt += `2. Provide a "Safety Risk Score" from 1 (Safe) to 10 (Critical).\n`;
    prompt += `3. List 3 immediate prioritized actions for the maintenance team.\n`;
    prompt += `\nFormat the output as professional, concise text.`;

    const parts: any[] = [{ text: prompt }];

    if (data.photoDamage) {
      const base64Data = data.photoDamage.split(',')[1];
      if (base64Data) {
        parts.push({
          inlineData: {
            mimeType: 'image/jpeg',
            data: base64Data
          }
        });
        parts.push({ text: "Also analyze the attached photo of the reported damage for severity." });
      }
    }

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: { parts },
    });

    return response.text || "Analysis complete but no text returned.";

  } catch (error) {
    console.error("Gemini Analysis Failed:", error);
    return "AI Safety Analysis currently unavailable. Please review the manual report.";
  }
};

