interface OnboardingWizardProps {
    user: User;
    appScriptUrl: string;
    onComplete: (updatedUser: User) => void;
}

const OnboardingWizard: React.FC<OnboardingWizardProps> = ({ user, appScriptUrl, onComplete }) => {
    const [step, setStep] = useState(0); // 0: Identity, 1: Security, 2: Notifications, 3: Success
    const [isLoading, setIsLoading] = useState(false);

    // Identity & Setup State
    const [fullName, setFullName] = useState(user.name || '');
    const [email, setEmail] = useState(user.username || '');
    const [newPassword, setNewPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [error, setError] = useState('');

    // Notifications
    const [prefs, setPrefs] = useState<UserPreferences>({
        emailNotifications: true,
        notifyGeneral: true,
        notifyPetroleum: true,
        notifyPetroleumV2: true,
        notifyAcid: true
    });

    const nextStep = () => {
        setError('');
        setStep(prev => prev + 1);
    };

    const handleStepSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (step === 0) {
            if (!fullName.trim()) { setError("Full Name is required."); return; }
            if (!email.trim() || !email.includes('@')) { setError("A valid email is required."); return; }
        }
        if (step === 1) {
            if (newPassword.length < 4) { setError("Password must be at least 4 characters."); return; }
            if (newPassword !== confirmPassword) { setError("Passwords do not match."); return; }
        }
        nextStep();
    };

    const handleFinalize = async () => {
        setIsLoading(true);
        setError('');
        try {
            const payload = {
                action: 'update_user',
                originalUsername: user.username, // Keep reference to old username for DB lookup
                username: email, // New username (email)
                name: fullName,
                password: newPassword,
                preferences: { ...prefs, hasCompletedTour: false }
            };

            const response = await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify(payload)
            });
            const result = await response.json();

            if (result.status === 'success') {
                setStep(3);
            } else {
                setError(result.message || "Failed to finalize profile. Please contact Support.");
            }
        } catch (err) {
            setError("Connection interrupted. Please try again.");
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="fixed inset-0 z-[200] bg-slate-900 flex items-center justify-center p-4 animate-fadeIn">
            <div className="max-w-4xl w-full bg-white rounded-3xl shadow-2xl overflow-hidden flex flex-col md:flex-row min-h-[600px]">

                {/* Left Branding Panel */}
                <div className="md:w-5/12 bg-emerald-950 p-10 flex flex-col justify-between text-white relative">
                    <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')] opacity-10"></div>
                    <div className="relative z-10">
                        <div className="w-12 h-12 bg-emerald-500 rounded-2xl flex items-center justify-center mb-8 shadow-lg shadow-emerald-500/20">
                            <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z"></path></svg>
                        </div>
                        <h1 className="text-3xl font-black mb-2 uppercase tracking-tight leading-none">Identity<br/>Activation</h1>
                        <p className="text-emerald-400 text-[10px] font-bold uppercase tracking-widest opacity-60">Security Protocol 4.1.0</p>
                    </div>

                    <div className="relative z-10 space-y-6">
                        {[
                            { s: 0, l: 'Your Profile' },
                            { s: 1, l: 'Secure Access' },
                            { s: 2, l: 'Connectivity' }
                        ].map(item => (
                            <div key={item.s} className={`flex items-center gap-4 transition-all duration-500 ${step >= item.s ? 'opacity-100 translate-x-0' : 'opacity-20 -translate-x-2'}`}>
                                <div className={`w-10 h-10 rounded-full flex items-center justify-center border-2 ${step > item.s ? 'bg-emerald-500 border-emerald-500 text-white' : step === item.s ? 'border-emerald-400 text-emerald-400' : 'border-emerald-800 text-emerald-800'} font-bold text-sm transition-colors`}>
                                    {step > item.s ? '✓' : item.s + 1}
                                </div>
                                <span className="font-bold text-[11px] uppercase tracking-[0.2em]">{item.l}</span>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Right Interactive Panel */}
                <div className="md:w-7/12 p-8 md:p-14 bg-white flex flex-col justify-center relative overflow-y-auto">

                    {step === 0 && (
                        <div className="animate-fadeIn">
                            <h2 className="text-2xl font-black text-slate-800 mb-2 uppercase tracking-tight">Identity Setup</h2>
                            <p className="text-slate-500 text-sm mb-8 font-medium leading-relaxed">Establish your professional identity. Your name will be used on all official compliance reports.</p>
                            <form onSubmit={handleStepSubmit} className="space-y-5">
                                <div>
                                    <label className="block text-[10px] font-black uppercase text-slate-400 mb-2 tracking-widest ml-1">Full Legal Name</label>
                                    <input 
                                        type="text" 
                                        autoFocus 
                                        required
                                        className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-4 focus:ring-emerald-500/10 focus:border-emerald-500 outline-none transition font-bold text-slate-800" 
                                        value={fullName} 
                                        onChange={e => setFullName(e.target.value.replace(/\b\w/g, c => c.toUpperCase()))} 
                                        placeholder="e.g. Johnathan Doe" 
                                    />
                                </div>
                                <div>
                                    <label className="block text-[10px] font-black uppercase text-slate-400 mb-2 tracking-widest ml-1">Login Email (Confirmation)</label>
                                    <input 
                                        type="email" 
                                        required
                                        className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-4 focus:ring-emerald-500/10 focus:border-emerald-500 outline-none transition font-bold text-slate-800" 
                                        value={email} 
                                        onChange={e => setEmail(e.target.value.toLowerCase())} 
                                        placeholder="yourname@company.com" 
                                    />
                                    <p className="text-[9px] text-slate-400 mt-2 ml-1 italic">Note: Changing this will update your primary login ID.</p>
                                </div>
                                {error && <div className="p-3 bg-red-50 border border-red-100 text-red-600 text-[10px] font-black uppercase rounded-lg">{error}</div>}
                                <button type="submit" className="w-full py-4 bg-slate-900 hover:bg-black text-white font-black rounded-xl shadow-xl transition-all active:scale-95 flex items-center justify-center gap-3 uppercase tracking-widest text-xs mt-4">
                                    Next Phase
                                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path d="M14 5l7 7m0 0l-7 7m7-7H3"></path></svg>
                                </button>
                            </form>
                        </div>
                    )}

                    {step === 1 && (
                        <div className="animate-fadeIn">
                            <h2 className="text-2xl font-black text-slate-800 mb-2 uppercase tracking-tight">Access Control</h2>
                            <p className="text-slate-500 text-sm mb-8 font-medium">Create a secure passphrase to protect your compliance credentials.</p>
                            <form onSubmit={handleStepSubmit} className="space-y-4">
                                <div className="space-y-4">
                                    <input type="password" autoFocus required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-4 focus:ring-emerald-500/10 outline-none font-bold text-slate-800" value={newPassword} onChange={e => setNewPassword(e.target.value)} placeholder="Enter New Password" />
                                    <input type="password" required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-4 focus:ring-emerald-500/10 outline-none font-bold text-slate-800" value={confirmPassword} onChange={e => setConfirmPassword(e.target.value)} placeholder="Confirm New Password" />
                                </div>
                                {error && <div className="text-red-600 text-[10px] font-black bg-red-50 p-3 rounded-lg border border-red-100 uppercase tracking-widest">{error}</div>}
                                <button type="submit" className="w-full py-4 bg-slate-900 hover:bg-black text-white font-black rounded-xl shadow-xl transition-all active:scale-95 flex items-center justify-center gap-2 uppercase tracking-widest text-xs mt-4">
                                    Continue to Settings
                                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path d="M14 5l7 7m0 0l-7 7m7-7H3"></path></svg>
                                </button>
                            </form>
                        </div>
                    )}

                    {step === 2 && (
                        <div className="animate-fadeIn">
                            <h2 className="text-2xl font-black text-slate-800 mb-2 uppercase tracking-tight">Stay Responsive</h2>
                            <p className="text-slate-500 text-sm mb-8 font-medium">Configure automated inspection triggers and safety broadcasts.</p>

                            <div className="space-y-4 mb-8">
                                <label className={`flex items-center justify-between p-5 rounded-2xl border-2 transition-all cursor-pointer ${prefs.emailNotifications ? 'bg-emerald-50 border-emerald-500' : 'bg-white border-slate-100'}`}>
                                    <div>
                                        <p className="text-sm font-black text-slate-800 uppercase tracking-tight">Compliance Alerts</p>
                                        <p className="text-[10px] text-emerald-600 font-bold uppercase tracking-wide">Essential for Fleet Health</p>
                                    </div>
                                    <input type="checkbox" className="w-6 h-6 rounded border-gray-300 text-emerald-600 focus:ring-emerald-500" checked={prefs.emailNotifications} onChange={() => setPrefs(p => ({...p, emailNotifications: !p.emailNotifications}))} />
                                </label>

                                <div className={`grid grid-cols-2 gap-3 transition-opacity ${!prefs.emailNotifications && 'opacity-30 pointer-events-none'}`}>
                                    {[
                                        { k: 'notifyGeneral', l: 'General' },
                                        { k: 'notifyPetroleum', l: 'Petro V1' },
                                        { k: 'notifyPetroleumV2', l: 'Petro V2' },
                                        { k: 'notifyAcid', l: 'Acid Checks' }
                                    ].map(m => (
                                        <label key={m.k} className="flex items-center justify-between p-4 bg-slate-50 rounded-xl border border-slate-100 cursor-pointer hover:bg-slate-100">
                                            <span className="text-[10px] font-black text-slate-500 uppercase tracking-wide">{m.l}</span>
                                            <input type="checkbox" className="w-4 h-4 rounded text-emerald-600" checked={prefs[m.k as keyof UserPreferences] as boolean} onChange={() => setPrefs(p => ({...p, [m.k]: !p[m.k as keyof UserPreferences]}))} />
                                        </label>
                                    ))}
                                </div>
                            </div>

                            {error && <div className="p-3 bg-red-50 border border-red-100 text-red-600 text-[10px] font-black uppercase rounded-lg mb-4">{error}</div>}

                            <button onClick={handleFinalize} disabled={isLoading} className="w-full py-5 bg-emerald-600 hover:bg-emerald-700 text-white font-black rounded-2xl shadow-2xl transition-all active:scale-95 flex items-center justify-center gap-3 uppercase tracking-widest text-[11px]">
                                {isLoading ? (
                                    <svg className="animate-spin h-5 w-5 text-white" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                                ) : (
                                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M5 13l4 4L19 7"></path></svg>
                                )}
                                {isLoading ? 'Activating Profile...' : 'Complete Activation'}
                            </button>
                        </div>
                    )}

                    {step === 3 && (
                        <div className="text-center animate-fadeIn">
                            <div className="w-24 h-24 bg-emerald-50 rounded-[2rem] flex items-center justify-center mx-auto mb-10 shadow-inner border border-emerald-100">
                                <svg className="w-12 h-12 text-emerald-600" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3.5"><path d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                            </div>
                            <h2 className="text-3xl font-black text-slate-800 mb-4 uppercase tracking-tighter">Profile Verified</h2>
                            <p className="text-slate-500 text-sm font-medium leading-relaxed mb-12 max-w-xs mx-auto">Your identity and security credentials have been established on the fleet server.</p>
                            <button 
                                onClick={() => onComplete({ ...user, username: email, name: fullName, preferences: prefs, needsSetup: false })} 
                                className="w-full py-5 bg-slate-900 hover:bg-black text-white font-black rounded-[1.5rem] shadow-2xl transition-all transform hover:scale-105 active:scale-95 uppercase tracking-[0.2em] text-[11px]"
                            >
                                Open Fleet Portal
                            </button>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

export default OnboardingWizard;

import {} from '../types';

// --- MODULAR BACKEND FILES FOR APPS SCRIPT ---

const CODE_CONTROLLER = `// =========================================================
// 1. CONTROLLER (Main Entry & Routing)
// =========================================================

function doPost(e) {
  const lock = LockService.getScriptLock();
  lock.tryLock(30000); 

  try {
    const ss = SpreadsheetApp.getActiveSpreadsheet();
    const body = e.postData ? JSON.parse(e.postData.contents) : {};

    // Trigger maintenance cleanup tasks on write actions only
    SystemHandlers.cleanupOldNotifications(ss);

    return routeRequest(ss, body);
  } catch (err) {
    return ResponseBuilder.error(err.toString());
  } finally {
    lock.releaseLock();
  }
}

function doGet(e) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  // Read-only GET request for heartbeat/syncing
  return DataHandlers.handleGetRequest(ss);
}

function routeRequest(ss, body) {
  const action = body.action;
  const routes = {
    'login': () => AuthHandlers.handleLogin(ss, body),
    'register_user': () => AuthHandlers.handleRegisterUser(ss, body),
    'get_users': () => AuthHandlers.handleGetUsers(ss),
    'delete_user': () => AuthHandlers.handleDeleteUser(ss, body),
    'update_user': () => AuthHandlers.handleUpdateUser(ss, body),
    'acknowledge_issue': () => SystemHandlers.handleAcknowledgeIssue(ss, body),
    'request_inspection': () => SystemHandlers.handleRequestInspection(ss, body), 
    'get_acknowledgements': () => SystemHandlers.handleGetAcknowledgements(ss),
    'mark_notification_read': () => SystemHandlers.handleMarkNotificationRead(ss, body),
    'update_settings': () => SystemHandlers.handleUpdateSettings(ss, body),
    'broadcast': () => SystemHandlers.handleBroadcast(ss, body),
    'extend_subscription': () => SubscriptionHandlers.handleExtendSubscription(ss, body),
    'submit_support_ticket': () => SupportHandlers.handleSubmitSupport(ss, body),
    'get_tickets': () => SupportHandlers.handleGetTickets(ss, body),
    'update_ticket': () => SupportHandlers.handleUpdateTicket(ss, body)
  };

  if (!action || action === 'create' || !routes[action]) {
    return DataHandlers.handleDataSubmission(ss, body);
  }
  return routes[action]();
}`;

const CODE_AUTH = `// =========================================================
// 2. AUTHENTICATION & USER MANAGEMENT
// =========================================================

const AuthHandlers = {
  handleLogin: function(ss, body) {
    const username = body.username ? String(body.username).trim().toLowerCase() : "";
    const password = body.password ? String(body.password) : "";
    let userSheet = ss.getSheetByName('Users');
    if (!userSheet || userSheet.getLastRow() <= 1) return ResponseBuilder.error("No users found.", "NO_USERS");

    const data = userSheet.getDataRange().getValues();
    for (let i = 1; i < data.length; i++) {
        const row = data[i];
        if (String(row[0]).trim().toLowerCase() === username) {
             const storedPassword = String(row[1]);
             const userName = row[2];

             // PERMISSIVE LOGIN FOR FIRST-TIMERS:
             // Allow login if password matches OR (user has no Name AND password is default/empty)
             const isInvited = !userName;
             const isDefaultPassword = (storedPassword === "1234" || storedPassword === "");

             const canLogin = (password === storedPassword) || (isInvited && (password === "" || isDefaultPassword));

             if (canLogin) {
                 const isEnabled = row[7] === undefined || row[7] === "" || String(row[7]).toUpperCase() === "TRUE";
                 if (!isEnabled) {
                     return ResponseBuilder.error("Account Access Disabled. Contact Administrator.", "ACCOUNT_DISABLED");
                 }

                 let prefs = {};
                 try { if (row[6]) prefs = JSON.parse(row[6]); } catch(e) {}
                 const user = { 
                    username: row[0], 
                    name: row[2], 
                    role: String(row[3]).trim(), 
                    position: row[4] || '', 
                    preferences: prefs, 
                    isActive: isEnabled 
                 };
                 userSheet.getRange(i + 1, 6).setValue(new Date().toISOString());
                 return ResponseBuilder.success({ user: user });
             }
        }
    }
    return ResponseBuilder.error("Invalid credentials.", "INVALID_CREDENTIALS");
  },

  handleRegisterUser: function(ss, body) {
    let userSheet = ss.getSheetByName('Users');
    if (!userSheet) {
        userSheet = ss.insertSheet('Users');
    }
    if (userSheet.getLastRow() === 0) {
        userSheet.appendRow(["Username", "Password", "Name", "Role", "Position", "Last_Login", "Preferences", "Enabled"]);
        userSheet.setFrozenRows(1);
    }
    const username = body.username ? String(body.username).trim().toLowerCase() : "";
    const data = userSheet.getDataRange().getValues();
    for(let i=1; i<data.length; i++) {
        if(String(data[i][0]).trim().toLowerCase() === username) return ResponseBuilder.error("User exists.");
    }
    const defaultPrefs = JSON.stringify({ emailNotifications: true, notifyGeneral: true, notifyPetroleum: true, notifyPetroleumV2: true, notifyAcid: true });
    // Invited users get "1234" as a secret default password
    userSheet.appendRow([username, body.password || "1234", body.name || "", String(body.role).trim(), body.position || "", new Date().toISOString(), defaultPrefs, "TRUE"]);
    return ResponseBuilder.success({ message: "User registered." });
  },

  handleGetUsers: function(ss) {
    let userSheet = ss.getSheetByName('Users');
    if (!userSheet) return ResponseBuilder.success({ users: [] });
    const data = userSheet.getDataRange().getValues();
    const users = [];
    for (let i = 1; i < data.length; i++) {
        const isEnabled = data[i][7] === undefined || data[i][7] === "" || String(data[i][7]).toUpperCase() === "TRUE";
        if (data[i][0]) users.push({ 
            username: data[i][0], 
            name: data[i][2], 
            role: data[i][3], 
            position: data[i][4], 
            lastLogin: data[i][5],
            isActive: isEnabled
        });
    }
    return ResponseBuilder.success({ users: users });
  },

  handleDeleteUser: function(ss, body) {
    let userSheet = ss.getSheetByName('Users');
    const username = String(body.username).toLowerCase();
    const data = userSheet.getDataRange().getValues();
    for (let i = 1; i < data.length; i++) {
        if (String(data[i][0]).toLowerCase() === username) {
            userSheet.deleteRow(i + 1);
            return ResponseBuilder.success();
        }
    }
    return ResponseBuilder.error("Not found");
  },

  handleUpdateUser: function(ss, body) {
    let userSheet = ss.getSheetByName('Users');
    const currentUsername = body.originalUsername ? String(body.originalUsername).toLowerCase() : String(body.username).toLowerCase();
    const data = userSheet.getDataRange().getValues();
    for (let i = 1; i < data.length; i++) {
        if (String(data[i][0]).toLowerCase() === currentUsername) {
            // Update Username if provided (Email Change)
            if (body.username) userSheet.getRange(i + 1, 1).setValue(String(body.username).toLowerCase());
            if (body.name !== undefined) userSheet.getRange(i + 1, 3).setValue(body.name);
            if (body.role) userSheet.getRange(i + 1, 4).setValue(String(body.role).trim());
            if (body.position !== undefined) userSheet.getRange(i + 1, 5).setValue(body.position);
            if (body.preferences) userSheet.getRange(i + 1, 7).setValue(JSON.stringify(body.preferences));
            if (body.password) userSheet.getRange(i + 1, 2).setValue(body.password);
            if (body.isActive !== undefined) userSheet.getRange(i + 1, 8).setValue(body.isActive ? "TRUE" : "FALSE");
            return ResponseBuilder.success();
        }
    }
    return ResponseBuilder.error("Not found");
  }
};`;

const CODE_CORE_OPS = `// =========================================================
// 3. CORE OPERATIONS (Data, Systems, Subscription)
// =========================================================

const DataHandlers = {
  handleDataSubmission: function(ss, body) {
    const sheetName = body.sheet;
    let sheet = ss.getSheetByName(sheetName);
    if (!sheet) {
      sheet = ss.insertSheet(sheetName);
    }
    if (sheet.getLastRow() === 0 && body.headers) {
      sheet.appendRow(body.headers);
      sheet.setFrozenRows(1);
    }
    sheet.appendRow(body.row.map(r => r === null ? "" : String(r)));

    if (body.requestId) {
        const reqSheet = ss.getSheetByName('Inspection_Requests');
        if (reqSheet) {
            const reqData = reqSheet.getDataRange().getValues();
            for (let i = 1; i < reqData.length; i++) {
                if (String(reqData[i][0]) === String(body.requestId)) {
                    reqSheet.getRange(i + 1, 10).setValue('Completed'); 
                    break;
                }
            }
        }
    }

    return ResponseBuilder.success({ sheet: sheetName });
  },

  handleGetRequest: function(ss) {
    const sheets = ss.getSheets();
    const data = {};
    sheets.forEach(sheet => {
      const name = sheet.getName();
      if (name === 'Users' || name === 'System_Logs') return;

      const lastRow = sheet.getLastRow();
      if (lastRow === 0) {
          data[name] = [];
          return;
      }

      if (name === 'Validation_Data') {
         const values = sheet.getDataRange().getValues();
         const columns = {};
         if (values.length > 0) {
             const headers = values[0];
             headers.forEach((h, idx) => {
                 columns[h] = values.slice(1).map(r => r[idx]).filter(v => v !== "");
             });
         }
         data[name] = columns;
      } else if (name === 'Acknowledgements') {
          data[name] = sheet.getRange(1, 1, lastRow, 1).getValues().flat().filter(v => v !== "");
      } else if (name === 'Subscription_Data') {
          const values = sheet.getDataRange().getValues();
          if (values.length > 1) {
            const history = [];
            for (let i = 1; i < values.length; i++) {
                const row = values[i];
                if (!row[2]) continue;

                let expiry = row[2];
                if (expiry instanceof Date) {
                  expiry = Utilities.formatDate(expiry, ss.getSpreadsheetTimeZone(), "yyyy-MM-dd");
                } else {
                  expiry = String(expiry).trim();
                  if (expiry === "" || expiry === "null") continue;
                }

                let ts = row[4];
                if (ts instanceof Date) ts = Utilities.formatDate(ts, ss.getSpreadsheetTimeZone(), "yyyy-MM-dd");
                else if (typeof ts === 'string') ts = ts.split('T')[0];

                history.push({
                    status: row[0] || "Expired",
                    plan: row[1] || "None",
                    expiryDate: expiry,
                    processedBy: row[3] || 'System',
                    timestamp: ts || ''
                });
            }
            const last = history.length > 0 ? history[history.length - 1] : { status: "Expired", plan: "None", expiryDate: "" };
            data[name] = { current: last, history: history };
          } else {
            data[name] = { current: { status: "Expired", plan: "None", expiryDate: "" }, history: [] };
          }
      } else if (name === 'System_Settings') {
          // Return only the data row for settings
          data[name] = sheet.getRange(1, 1, Math.min(2, lastRow), sheet.getLastColumn()).getValues();
      } else {
         const startRow = Math.max(1, lastRow - 150);
         data[name] = sheet.getRange(startRow, 1, lastRow - startRow + 1, sheet.getLastColumn()).getValues();
      }
    });
    return ContentService.createTextOutput(JSON.stringify(data)).setMimeType(ContentService.MimeType.JSON);
  }
};

const SystemHandlers = {
  handleRequestInspection: function(ss, body) {
    let sheet = ss.getSheetByName('Inspection_Requests');
    if (!sheet) {
        sheet = ss.insertSheet('Inspection_Requests');
        sheet.appendRow(['ID', 'Requester', 'Role', 'Truck', 'Trailer', 'Type', 'Reason', 'Priority', 'Assigned_To', 'Status', 'Timestamp']);
        sheet.setFrozenRows(1);
    }
    const id = "REQ-" + Date.now().toString().slice(-6);
    const ts = new Date().toISOString();
    sheet.appendRow([
        id, 
        body.requester || 'System', 
        body.role || 'Admin', 
        body.truckNo, 
        body.trailerNo || '', 
        body.type || 'General', 
        body.reason || '', 
        body.priority || 'Normal', 
        body.assignedInspector || 'Unassigned', 
        'Pending', 
        ts
    ]);

    const msg = "New Inspection Requested: Truck " + body.truckNo + " (" + (body.priority || 'Normal') + ")";
    const actionLink = "request:start_inspection|" + body.type + "|" + body.truckNo + "|" + (body.trailerNo || '') + "|" + body.requester + "|" + (body.reason || '');

    SystemHandlers.handleBroadcast(ss, {
        type: (body.priority === 'Urgent' || body.priority === 'Safety Concern') ? 'critical' : 'info',
        message: msg,
        recipient: 'inspector',
        action: id + "-" + actionLink
    });

    return ResponseBuilder.success({ requestId: id });
  },

  handleUpdateSettings: function(ss, body) {
    let sheet = ss.getSheetByName('System_Settings');
    if (!sheet) {
        sheet = ss.insertSheet('System_Settings');
        sheet.appendRow(["Company_Name", "Admin_Email", "Last_Updated", "Updated_By", "Logo", "APK_Link", "Web_URL", "Maint_Mode", "Maint_Msg"]);
        sheet.setFrozenRows(1);
    }

    // PERSISTENCE FIX: Overwrite Row 2 instead of appending. 
    // This stops the settings sheet from "updating itself" with redundant rows.
    const rowData = [
        body.companyName || '', 
        body.managerEmail || '', 
        new Date().toISOString(), 
        body.updatedBy || 'Admin',
        body.companyLogo || '',
        body.mobileApkLink || '',
        body.webAppUrl || '',
        body.maintenanceMode === true ? "TRUE" : "FALSE",
        body.maintenanceMessage || ''
    ];

    sheet.getRange(2, 1, 1, rowData.length).setValues([rowData]);
    return ResponseBuilder.success();
  },

  cleanupOldNotifications: function(ss) {
    const sheetsToClean = ['SystemNotification', 'Acknowledgements'];
    const now = new Date().getTime();
    const oneDay = 24 * 60 * 60 * 1000;

    sheetsToClean.forEach(name => {
        const sheet = ss.getSheetByName(name);
        if (!sheet) return;
        const data = sheet.getDataRange().getValues();
        if (data.length <= 1) return;
        const tsColIdx = (name === 'SystemNotification') ? 4 : 3;
        for (let i = data.length - 1; i >= 1; i--) {
            const tsValue = data[i][tsColIdx];
            if (!tsValue) continue;
            const ts = new Date(tsValue).getTime();
            if (now - ts > oneDay) {
                sheet.deleteRow(i + 1);
            }
        }
    });
  },

  handleBroadcast: function(ss, body) {
    let sheet = ss.getSheetByName('SystemNotification');
    if (!sheet) {
        sheet = ss.insertSheet('SystemNotification');
        sheet.appendRow(["ID", "Recipient", "Type", "Message", "Timestamp", "IsRead", "Action"]);
        sheet.setFrozenRows(1);
    }
    sheet.appendRow([
        "SYS-" + Date.now(), 
        body.recipient || "all", 
        body.type || "info", 
        body.message, 
        new Date().toISOString(), 
        "FALSE", 
        body.action || ""
    ]);
    return ResponseBuilder.success();
  },

  handleAcknowledgeIssue: function(ss, body) {
    let sheet = ss.getSheetByName('Acknowledgements');
    if (!sheet) {
        sheet = ss.insertSheet('Acknowledgements');
        sheet.appendRow(['Issue_ID', 'User', 'Role', 'Timestamp']);
        sheet.setFrozenRows(1);
    }
    sheet.appendRow([String(body.issueId), body.user, body.role, new Date().toISOString()]);
    return ResponseBuilder.success();
  },

  handleGetAcknowledgements: function(ss) {
      let sheet = ss.getSheetByName('Acknowledgements');
      if (!sheet) return ResponseBuilder.success({ data: [] });
      const data = sheet.getDataRange().getValues();
      return ResponseBuilder.success({ data: data.slice(1).map(r => r[0]) });
  },

  handleMarkNotificationRead: function(ss, body) {
    const sheet = ss.getSheetByName('SystemNotification');
    if (!sheet) return ResponseBuilder.error("No sheet");
    const data = sheet.getDataRange().getValues();
    for (let i = 1; i < data.length; i++) {
        if (String(data[i][0]) === String(body.id)) {
            sheet.getRange(i + 1, 6).setValue("TRUE");
            return ResponseBuilder.success();
        }
    }
    return ResponseBuilder.error("Not found");
  }
};

const SubscriptionHandlers = {
  handleExtendSubscription: function(ss, body) {
    let sheet = ss.getSheetByName('Subscription_Data');
    if (!sheet) {
      sheet = ss.insertSheet('Subscription_Data');
    }
    if (sheet.getLastRow() === 0 || sheet.getRange(1,1).getValue() === "") {
      sheet.getRange(1, 1, 1, 5).setValues([["Status", "Plan", "ExpiryDate", "ProcessedBy", "Timestamp"]]);
      sheet.setFrozenRows(1);
    }
    sheet.appendRow(["Active", body.plan || "Enterprise", body.expiryDate, body.processedBy || "Admin", new Date()]);
    return ResponseBuilder.success({ message: "Subscription extended successfully" });
  }
};`;

const CODE_LIB = `const ResponseBuilder = {
  success: function(data = {}) { return this.build({ status: "success", ...data }); },
  error: function(message, code) { return this.build({ status: "error", message: message, code: code }); },
  build: function(data) { return ContentService.createTextOutput(JSON.stringify(data)).setMimeType(ContentService.MimeType.JSON); }
};`;

export const BACKEND_FILES: Record<string, string> = {
    '1_Controller.gs': CODE_CONTROLLER,
    '2_Auth.gs': CODE_AUTH,
    '3_Core.gs': CODE_CORE_OPS,
    '5_Utils.gs': CODE_LIB
};

export const BACKEND_SCRIPT_TEMPLATE = Object.values(BACKEND_FILES).join('\n\n');

import React, { useState, useEffect, useMemo } from 'react';
