interface LauncherTileProps {
    id: string;
    label: string;
    icon: React.ReactNode;
    isForcedLock?: boolean;
    badgeCount?: number;
    badgeColor?: string;
    isInspectionModule?: boolean;
    isLocked: boolean;
    isPro?: boolean;
    isEnterprise?: boolean;
    onNavigate: (module: string) => void;
}

const LauncherTile = ({ 
    id, 
    label, 
    icon, 
    isForcedLock = false, 
    badgeCount = 0,
    badgeColor = 'bg-slate-900',
    isInspectionModule = false,
    isLocked,
    isPro = false,
    isEnterprise = false,
    onNavigate
}: LauncherTileProps) => {
    const effectiveLock = isForcedLock || (isInspectionModule && isLocked);

    return (
        <button 
            onClick={() => !effectiveLock && onNavigate(id)}
            className={`flex flex-col items-center justify-center p-2 transition-all w-full group ${effectiveLock ? 'opacity-25 cursor-not-allowed' : 'hover:opacity-60 active:scale-95'}`}
        >
            <div className="relative mb-5">
                {icon}
                {effectiveLock && (
                    <div className="absolute -top-1 -right-1 bg-slate-900 text-white rounded-full p-1 shadow-sm scale-75 sm:scale-100 border border-white">
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2"><path d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z"></path></svg>
                    </div>
                )}
                {isEnterprise && !effectiveLock && (
                    <div className="absolute -top-1 -right-1 bg-indigo-600 text-white text-[7px] font-black px-1.5 py-0.5 rounded border border-white shadow-sm italic uppercase tracking-tighter">
                        enterprise
                    </div>
                )}
                {isPro && !isEnterprise && !effectiveLock && (
                    <div className="absolute -top-1 -right-1 bg-blue-600 text-white text-[8px] font-bold px-2 py-0.5 rounded border border-white shadow-sm italic">
                        pro
                    </div>
                )}
                {badgeCount > 0 && !effectiveLock && (
                    <div className={`absolute -top-1 -right-1 ${badgeColor} text-white text-[10px] font-bold px-2.5 py-0.5 rounded-full border border-white shadow-sm`}>
                        {badgeCount}
