                )}
            </div>
            <span className={`text-[10px] sm:text-[12px] font-medium text-center tracking-wider leading-tight transition-colors w-full whitespace-normal px-2 ${effectiveLock ? 'text-slate-300' : 'text-slate-900 group-hover:text-blue-600'}`}>
                {label}
            </span>
        </button>
    );
};

