    onNavigate
}: LauncherTileProps) => {
    const effectiveLock = isForcedLock || (isInspectionModule && isLocked);

    return (
        <button 
            onClick={() => !effectiveLock && onNavigate(id)}
            className={`flex flex-col items-center justify-center p-2 transition-all w-full group ${effectiveLock ? 'opacity-25 cursor-not-allowed' : 'hover:opacity-60 active:scale-95'}`}
