import React, { useState, useRef } from 'react';
import { ValidationLists } from '../types';

interface FleetRegistryViewProps {
    appScriptUrl: string;
    validationLists: ValidationLists;
    onRefresh: () => void;
    showToast: (msg: string, type: 'success' | 'error' | 'info') => void;
    isLocked?: boolean;
}

const FleetRegistryView: React.FC<FleetRegistryViewProps> = ({ 
    appScriptUrl, validationLists, onRefresh, showToast, isLocked 
}) => {
    const [newTruck, setNewTruck] = useState('');
    const [newTrailer, setNewTrailer] = useState('');
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [isImporting, setIsImporting] = useState(false);
    const fileInputRef = useRef<HTMLInputElement>(null);

    const handleAddAsset = async (type: 'truck' | 'trailer') => {
        const val = type === 'truck' ? newTruck : newTrailer;
        if (!val.trim()) return;
        if (isLocked) {
            showToast("System locked. Changes not allowed.", "error");
            return;
        }

        setIsSubmitting(true);
        try {
            const payload = {
                action: 'manage_fleet',
                type: type,
                value: val.trim().toUpperCase()
            };

            await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify(payload),
                mode: 'no-cors'
            });

            showToast(`${type === 'truck' ? 'Truck' : 'Trailer'} added to registry`, "success");
            if (type === 'truck') setNewTruck('');
            else setNewTrailer('');

            setTimeout(onRefresh, 1000);
        } catch (e) {
            showToast("Failed to save asset.", "error");
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = async (event) => {
            const content = event.target?.result as string;
            if (!content) return;

            setIsImporting(true);
            try {
                // Simple CSV parsing
                const lines = content.split(/\r?\n/);
                const trucks: string[] = [];
                const trailers: string[] = [];

                // Skip header (Assumes first row is "Truck,Trailer")
                for (let i = 1; i < lines.length; i++) {
                    const line = lines[i].trim();
                    if (!line) continue;

                    const [truck, trailer] = line.split(',').map(s => s?.trim().toUpperCase() || "");
                    if (truck) trucks.push(truck);
                    if (trailer) trailers.push(trailer);
                }

                if (trucks.length === 0 && trailers.length === 0) {
                    showToast("No data found in file.", "warning");
                    setIsImporting(false);
                    return;
                }

                const payload = {
                    action: 'bulk_manage_fleet',
                    trucks,
                    trailers
                };

                await fetch(appScriptUrl, {
                    method: 'POST',
                    body: JSON.stringify(payload),
                    mode: 'no-cors'
                });

                showToast(`Imported ${trucks.length} trucks and ${trailers.length} trailers.`, "success");
                setTimeout(onRefresh, 1500);
            } catch (err) {
                showToast("Failed to parse or upload file.", "error");
            } finally {
                setIsImporting(false);
                if (fileInputRef.current) fileInputRef.current.value = "";
            }
        };
        reader.readAsText(file);
    };

    return (
        <div className="max-w-6xl mx-auto space-y-12 animate-fadeIn py-4 px-4 sm:px-0 font-sans">
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <div>
                    <h2 className="text-3xl font-black text-slate-800 uppercase tracking-tight">Fleet Registry</h2>
