import React, { useState, useEffect } from 'react';
import { InspectionData, InspectionStatus, InspectionItemConfig, ValidationLists, SystemSettings } from '../types';
import { INSPECTION_ITEMS, INSPECTION_CATEGORIES, PETROLEUM_INSPECTION_ITEMS, PETROLEUM_CATEGORIES, ACID_INSPECTION_ITEMS, ACID_CATEGORIES, PETROLEUM_V2_ITEMS, PETROLEUM_V2_CATEGORIES, SECTIONS } from '../constants';
import CameraCapture from '../components/CameraCapture';
import SignaturePad from '../components/SignaturePad';
import StatusButton from '../components/ui/StatusButton';
import Input from '../components/ui/Input';
import AutocompleteInput from '../components/ui/AutocompleteInput';

interface InspectionFormViewProps {
    initialData: InspectionData;
    activeModule: string;
    validationLists: ValidationLists;
    settings: SystemSettings;
    onSaveDraft: (data: InspectionData) => void;
    onSubmit: (data: InspectionData) => void;
    onExit: () => void;
    submissionStatus: 'idle' | 'submitting' | 'success' | 'offline_saved';
    onViewReport: (data: InspectionData) => void;
}

const InspectionFormView: React.FC<InspectionFormViewProps> = ({ 
    initialData, activeModule, validationLists, settings, onSaveDraft, onSubmit, onExit, submissionStatus, onViewReport 
}) => {
    const [formData, setFormData] = useState<InspectionData & any>(initialData);
    const [currentSection, setCurrentSection] = useState(0);
    const [errors, setErrors] = useState<Record<string, boolean>>({});
    const [showDraftSaved, setShowDraftSaved] = useState(false);

    const updateField = (field: string, value: any) => {
        setFormData((prev: any) => ({ ...prev, [field]: value }));
        if (errors[field]) {
            setErrors(prev => {
                const next = {...prev};
                delete next[field];
                return next;
            });
        }
    };

    const handleSaveDraftLocal = () => {
        onSaveDraft(formData);
        setShowDraftSaved(true);
        setTimeout(() => setShowDraftSaved(false), 2000);
    };

    const getItemsForStep = (stepIndex: number): InspectionItemConfig[] => {
        let categories: string[] = [];
        let sourceItems: InspectionItemConfig[] = [];

        if (activeModule === 'general') sourceItems = INSPECTION_ITEMS;
        else if (activeModule === 'petroleum') sourceItems = PETROLEUM_INSPECTION_ITEMS;
        else if (activeModule === 'petroleum_v2') sourceItems = PETROLEUM_V2_ITEMS;
        else if (activeModule === 'acid') sourceItems = ACID_INSPECTION_ITEMS;

        if (activeModule === 'general') {
            if (stepIndex === 2) categories = [INSPECTION_CATEGORIES.PPE, INSPECTION_CATEGORIES.DOCUMENTATION];
            if (stepIndex === 3) categories = [INSPECTION_CATEGORIES.VEHICLE_EXTERIOR, INSPECTION_CATEGORIES.LIGHTS_ELECTRICAL];
            if (stepIndex === 4) categories = [INSPECTION_CATEGORIES.MECHANICAL, INSPECTION_CATEGORIES.TRAILER];
        } else if (activeModule === 'petroleum') {
            if (stepIndex === 2) categories = [PETROLEUM_CATEGORIES.TRUCK_EQUIPMENT];
            if (stepIndex === 3) categories = [PETROLEUM_CATEGORIES.TYRES, PETROLEUM_CATEGORIES.PPE_ID];
            if (stepIndex === 4) categories = [PETROLEUM_CATEGORIES.DOCUMENTS, PETROLEUM_CATEGORIES.ONBOARD];
        } else if (activeModule === 'petroleum_v2') {
            if (stepIndex === 2) categories = [PETROLEUM_V2_CATEGORIES.PRIME_MOVER];
            if (stepIndex === 3) categories = [PETROLEUM_V2_CATEGORIES.TRAILER_TANKS];
            if (stepIndex === 4) categories = [PETROLEUM_V2_CATEGORIES.DRIVER, PETROLEUM_V2_CATEGORIES.SAFETY_SIGNS, PETROLEUM_V2_CATEGORIES.DOCUMENTS];
        } else if (activeModule === 'acid') {
            if (stepIndex === 2) categories = [ACID_CATEGORIES.PPE];
            if (stepIndex === 3) categories = [ACID_CATEGORIES.VEHICLE];
            if (stepIndex === 4) categories = [ACID_CATEGORIES.SPILL_KIT, ACID_CATEGORIES.DOCUMENTATION];
        }

        return sourceItems.filter(item => categories.includes(item.category));
    };

    const validateSection = (sectionIndex: number): boolean => {
        const newErrors: Record<string, boolean> = {};

        if (sectionIndex === 0) {
            if (!formData.truckNo) newErrors.truckNo = true;
            if (!formData.trailerNo) newErrors.trailerNo = true;
            if (!formData.driverName) newErrors.driverName = true;
            if (!formData.location) newErrors.location = true;
            if (!formData.odometer) newErrors.odometer = true;
            if (activeModule !== 'general' && !formData.jobCard) newErrors.jobCard = true;
        }

        if (sectionIndex >= 2 && sectionIndex <= 4) {
            const requiredItems = getItemsForStep(sectionIndex);
            requiredItems.forEach(item => {
                if (!formData[item.id]) newErrors[item.id] = true;
            });
        }

        if (sectionIndex === 5) {
             if (!formData.remarks || formData.remarks.trim() === '') newErrors.remarks = true;
             if (!formData.rate || formData.rate === 0) newErrors.rate = true;
             if (!formData.inspectorSignature) newErrors.inspectorSignature = true;
             if (!formData.driverSignature) newErrors.driverSignature = true;
        }

        if (Object.keys(newErrors).length > 0) {
            setErrors(newErrors);
            window.scrollTo({ top: 0, behavior: 'smooth' }); 
            return false;
        }

        setErrors({});
        return true;
    };

    const validateFullForm = (): boolean => {
        for (let i = 0; i <= 5; i++) {
            if (!validateSection(i)) {
                setCurrentSection(i); 
                return false;
            }
        }
        return true;
    };

    const handleNext = () => {
        if (!validateSection(currentSection)) return;
        window.scrollTo({ top: 0, behavior: 'smooth' });
        setCurrentSection(prev => Math.min(prev + 1, SECTIONS.length - 1));
    };

    const handleBack = () => {
        if (currentSection === 0) {
            onExit();
        } else {
            window.scrollTo({ top: 0, behavior: 'smooth' });
            setCurrentSection(prev => Math.max(prev - 1, 0));
        }
    };

    const handleSubmitInspection = () => {
        if (validateFullForm()) {
            onSubmit(formData);
        }
    };

    const renderDetailsSection = () => (
      <div className="space-y-6 animate-fadeIn">
        {formData.requestId && (
            <div className="bg-gradient-to-r from-indigo-600 to-indigo-800 p-5 rounded-2xl shadow-xl flex items-center justify-between text-white border border-indigo-400/30">
                <div className="flex items-center gap-4">
                    <div className="p-2.5 bg-white/10 rounded-xl backdrop-blur-md">
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-3 7h3m-3 4h3m-6-4h.01M9 16h.01"></path></svg>
                    </div>
                    <div>
                        <p className="text-[10px] font-black uppercase tracking-widest text-indigo-200">Active Mission</p>
                        <p className="text-base font-black tracking-tight uppercase">Request ID: {formData.requestId}</p>
                    </div>
                </div>
            </div>
        )}

        <div className="bg-white p-6 sm:p-8 rounded-3xl shadow-sm border border-slate-100">
          <h2 className="text-2xl font-black text-slate-800 mb-8 uppercase tracking-tight">Vehicle Identity</h2>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-y-8 gap-x-10">
            <AutocompleteInput label="Truck Reg No *" value={formData.truckNo} onChange={v => updateField('truckNo', v)} options={validationLists.trucks} placeholder="e.g. ABC 123" isRegNo={true} error={errors.truckNo} />
            <AutocompleteInput label="Trailer No *" value={formData.trailerNo} onChange={v => updateField('trailerNo', v)} options={validationLists.trailers} placeholder="e.g. T-100" isRegNo={true} error={errors.trailerNo} />
            <Input label="Job Card Reference" value={formData.jobCard || ''} onChange={v => updateField('jobCard', v)} error={errors.jobCard} />
            <AutocompleteInput label="Primary Inspector" value={formData.inspectedBy} onChange={v => updateField('inspectedBy', v)} options={validationLists.inspectors} isTitleCase={true} readOnly={true} />
            <AutocompleteInput label="Driver Name *" value={formData.driverName} onChange={v => updateField('driverName', v)} options={validationLists.drivers} placeholder="Verified Identity" isTitleCase={true} error={errors.driverName} />
            <AutocompleteInput label="Station Location *" value={formData.location} onChange={v => updateField('location', v)} options={validationLists.locations} placeholder="Hub" isTitleCase={true} error={errors.location} />
            <Input label="Odometer Readout (km) *" type="number" value={formData.odometer} onChange={v => updateField('odometer', v)} error={errors.odometer} />
          </div>
        </div>
      </div>
    );

    const renderPhotosSection = () => (
      <div className="space-y-6 animate-fadeIn">
         <div className="bg-white p-6 sm:p-8 rounded-3xl shadow-sm border border-slate-100">
          <h2 className="text-2xl font-black text-slate-800 mb-8 uppercase tracking-tight">Visual Documentation</h2>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
            <CameraCapture label="Horse: Front" existingImage={formData.photoFront} onCapture={img => updateField('photoFront', img)} />
            <CameraCapture label="Horse: Left Profile" existingImage={formData.photoLS} onCapture={img => updateField('photoLS', img)} />
            <CameraCapture label="Horse: Right Profile" existingImage={formData.photoRS} onCapture={img => updateField('photoRS', img)} />
            <CameraCapture label="Trailer: Rear Aspect" existingImage={formData.photoBack} onCapture={img => updateField('photoBack', img)} />
          </div>
        </div>
      </div>
    );

    const renderInspectionSection = (categoriesToShow: string[]) => {
        const itemsToRender = getItemsForStep(currentSection).filter(i => categoriesToShow.includes(i.category));
        const grouping: Record<string, InspectionItemConfig[]> = {};
        categoriesToShow.forEach(cat => {
            grouping[cat] = itemsToRender.filter(i => i.category === cat);
        });

        return (
          <div className="space-y-10 animate-fadeIn">
            {categoriesToShow.map(cat => (
              <div key={cat} className="bg-white rounded-[2rem] shadow-sm border border-slate-100 overflow-hidden">
                <div className="bg-slate-50 px-8 py-5 border-b border-slate-100 flex justify-between items-center">
                  <h3 className="text-[11px] font-black text-slate-500 uppercase tracking-[0.25em]">{cat}</h3>
                  <span className="text-[8px] font-black bg-rose-50 text-rose-500 px-2 py-1 rounded uppercase tracking-widest border border-rose-100">Verification Req.</span>
                </div>
                <div className="divide-y divide-slate-50">
                  {grouping[cat].map(item => (
                    <div key={item.id} className={`p-6 sm:p-8 transition-colors ${errors[item.id] ? 'bg-rose-50/40' : 'hover:bg-slate-50/30'}`}>
                      <div className="mb-5">
                          <span className={`font-bold text-sm leading-tight uppercase tracking-tight ${errors[item.id] ? 'text-rose-800' : 'text-slate-700'}`}>
                              {item.label}
                          </span>
                      </div>
                      <div className="flex gap-2 sm:gap-4 max-w-xl">
                         <StatusButton label="Compliant" status={InspectionStatus.GOOD} current={formData[item.id]} onClick={() => updateField(item.id, InspectionStatus.GOOD)} colorClass="green" />
                         <StatusButton label="Fault" status={InspectionStatus.BAD} current={formData[item.id]} onClick={() => updateField(item.id, InspectionStatus.BAD)} colorClass="red" />
                         <StatusButton label="Review" status={InspectionStatus.ATTENTION} current={formData[item.id]} onClick={() => updateField(item.id, InspectionStatus.ATTENTION)} colorClass="yellow" />
                         <StatusButton label="N/A" status={InspectionStatus.NIL} current={formData[item.id]} onClick={() => updateField(item.id, InspectionStatus.NIL)} colorClass="gray" />
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            ))}
          </div>
        );
    };

    const renderSignaturesSection = () => (
      <div className="space-y-6 animate-fadeIn">
        <div className="bg-white p-6 sm:p-8 rounded-3xl shadow-sm border border-slate-100">
          <h2 className="text-2xl font-black text-slate-800 mb-8 uppercase tracking-tight">Authorization</h2>

          <div className="mb-10">
            <label className={`block text-[10px] font-black uppercase mb-3 tracking-[0.2em] ${errors.remarks ? 'text-rose-600' : 'text-slate-400'}`}>Inspector Findings & Remarks *</label>
            <textarea className="w-full p-6 border rounded-2xl h-44 outline-none font-medium text-sm border-slate-200 focus:ring-4 focus:ring-indigo-50 bg-slate-50 transition-all resize-none" placeholder="Detailed vehicle condition summary..." value={formData.remarks} onChange={(e) => updateField('remarks', e.target.value)} />
          </div>

          <div className="mb-12">
             <label className="block text-[10px] font-black uppercase mb-5 tracking-[0.2em] text-slate-400">Final Health Grade *</label>
             <div className="flex gap-3 sm:gap-5 flex-wrap">
               {[1, 2, 3, 4, 5].map(num => (
                 <button key={num} type="button" onClick={() => updateField('rate', num)} className={`w-14 h-14 rounded-2xl font-black text-xl transition-all active:scale-90 ${formData.rate === num ? 'bg-slate-900 text-white shadow-2xl scale-110' : 'bg-slate-100 text-slate-400 hover:bg-slate-200'}`}>{num}</button>
               ))}
             </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-10 pt-10 border-t border-slate-100">
             <SignaturePad label="Inspector Authentication" existingSignature={formData.inspectorSignature} onSave={sig => updateField('inspectorSignature', sig)} />
             <SignaturePad label="Driver Confirmation" existingSignature={formData.driverSignature} onSave={sig => updateField('driverSignature', sig)} />
          </div>
        </div>
      </div>
    );

    const renderSummarySection = () => (
      <div className="space-y-6 animate-fadeIn pb-12">
        <div className="bg-white p-10 rounded-[2.5rem] shadow-sm border border-slate-100 text-center">
          <div className="w-20 h-20 bg-emerald-50 rounded-full flex items-center justify-center mx-auto mb-8 border border-emerald-100">
              <svg className="w-10 h-10 text-emerald-500" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
          </div>
          <h2 className="text-3xl font-black text-slate-800 mb-3 uppercase tracking-tight">Audit Ready</h2>
          <p className="text-slate-400 font-medium text-sm max-w-md mx-auto">Please perform a final data review. Submitting will permanently log this record into the corporate fleet repository.</p>
        </div>

        <div className="mt-8 bg-slate-900 rounded-[2.5rem] p-10 text-white shadow-2xl relative overflow-hidden group">
            <div className="absolute top-0 right-0 w-64 h-64 bg-emerald-500/10 rounded-full -mr-20 -mt-20 blur-3xl"></div>
            <div className="relative z-10 flex flex-col md:flex-row items-center justify-between gap-10">
                <div className="text-center md:text-left">
                    <h3 className="text-2xl font-black mb-1 text-white uppercase tracking-tight">Synchronize Records</h3>
                    <p className="text-emerald-400 text-xs font-black uppercase tracking-[0.25em] opacity-80">Transmit to HQ Database</p>
                </div>
                <button onClick={handleSubmitInspection} disabled={submissionStatus !== 'idle'} className={`w-full md:w-auto px-12 py-5 text-white rounded-2xl font-black text-lg shadow-2xl transition-all flex items-center justify-center gap-4 active:scale-95 border-2 border-white/10 uppercase tracking-[0.2em] ${submissionStatus !== 'idle' ? 'bg-slate-700' : 'bg-emerald-600 hover:bg-emerald-500'}`}>
                    {submissionStatus === 'submitting' ? 'Uploading...' : submissionStatus === 'offline_saved' ? 'Stored Locally' : 'Submit Inspection'}
                    {submissionStatus === 'idle' && <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>}
                </button>
            </div>
        </div>
      </div>
    );

    return (
        <div className="flex flex-col min-h-[calc(100vh-56px)] bg-slate-50/50 overflow-x-hidden">
             <div className="bg-white border-b border-slate-100 sticky top-14 z-30 shadow-sm">
                <div className="w-full">
                    <div className="flex px-4 py-5 justify-between md:justify-center items-center overflow-x-hidden">
                    {SECTIONS.map((section, idx) => {
                        const isActive = idx === currentSection;
                        const isCompleted = idx < currentSection;
                        return (
                        <div key={section.id} className="flex items-center flex-1 md:flex-none">
                            <div className="flex flex-col items-center gap-2 transition-all w-full">
                                <div className={`
                                    w-7 h-7 sm:w-9 sm:h-9 rounded-xl flex items-center justify-center text-[10px] sm:text-xs font-black transition-all duration-500
                                    ${isActive ? 'bg-slate-900 text-white shadow-xl scale-110' : isCompleted ? 'bg-emerald-500 text-white' : 'bg-slate-100 text-slate-300'}
                                `}>
                                    {isCompleted ? '✓' : idx + 1}
                                </div>
                                <span className={`hidden sm:block text-[8px] uppercase font-black tracking-[0.2em] ${isActive ? 'text-slate-900' : 'text-slate-300'}`}>
                                    {section.title}
                                </span>
                            </div>
                            {idx < SECTIONS.length - 1 && (
                            <div className={`h-0.5 flex-1 md:w-12 mx-1 sm:mx-4 rounded-full ${isCompleted ? 'bg-emerald-500' : 'bg-slate-100'}`} />
                            )}
                        </div>
                        );
                    })}
                    </div>
                </div>
            </div>

            <div className="flex-1 p-4 sm:p-8 md:p-12 w-full max-w-5xl mx-auto overflow-x-hidden">
                {currentSection === 0 && renderDetailsSection()}
                {currentSection === 1 && renderPhotosSection()}

                {activeModule === 'general' && currentSection === 2 && renderInspectionSection([INSPECTION_CATEGORIES.PPE, INSPECTION_CATEGORIES.DOCUMENTATION])}
                {activeModule === 'general' && currentSection === 3 && renderInspectionSection([INSPECTION_CATEGORIES.VEHICLE_EXTERIOR, INSPECTION_CATEGORIES.LIGHTS_ELECTRICAL])}
                {activeModule === 'general' && currentSection === 4 && renderInspectionSection([INSPECTION_CATEGORIES.MECHANICAL, INSPECTION_CATEGORIES.TRAILER])}

                {activeModule === 'petroleum' && currentSection === 2 && renderInspectionSection([PETROLEUM_CATEGORIES.TRUCK_EQUIPMENT])}
                {activeModule === 'petroleum' && currentSection === 3 && renderInspectionSection([PETROLEUM_CATEGORIES.TYRES, PETROLEUM_CATEGORIES.PPE_ID])}
                {activeModule === 'petroleum' && currentSection === 4 && renderInspectionSection([PETROLEUM_CATEGORIES.DOCUMENTS, PETROLEUM_CATEGORIES.ONBOARD])}

                {activeModule === 'petroleum_v2' && currentSection === 2 && renderInspectionSection([PETROLEUM_V2_CATEGORIES.PRIME_MOVER])}
                {activeModule === 'petroleum_v2' && currentSection === 3 && renderInspectionSection([PETROLEUM_V2_CATEGORIES.TRAILER_TANKS])}
                {activeModule === 'petroleum_v2' && currentSection === 4 && renderInspectionSection([PETROLEUM_V2_CATEGORIES.DRIVER, PETROLEUM_V2_CATEGORIES.SAFETY_SIGNS, PETROLEUM_V2_CATEGORIES.DOCUMENTS])}

                {activeModule === 'acid' && currentSection === 2 && renderInspectionSection([ACID_CATEGORIES.PPE])}
                {activeModule === 'acid' && currentSection === 3 && renderInspectionSection([ACID_CATEGORIES.VEHICLE])}
                {activeModule === 'acid' && currentSection === 4 && renderInspectionSection([ACID_CATEGORIES.SPILL_KIT, ACID_CATEGORIES.DOCUMENTATION])}

                {currentSection === 5 && renderSignaturesSection()}
                {currentSection === 6 && renderSummarySection()}
            </div>

            <footer className="bg-white border-t border-slate-100 p-5 sm:p-8 sticky bottom-0 z-30 shadow-2xl backdrop-blur-md bg-white/90">
              <div className="max-w-5xl mx-auto flex justify-between gap-4">
                <button onClick={handleBack} className="px-8 py-4 rounded-2xl border border-slate-200 font-black text-slate-400 hover:text-slate-800 hover:bg-slate-50 transition-all text-[10px] uppercase tracking-widest active:scale-95">
                    {currentSection === 0 ? 'Exit' : 'Previous'}
                </button>
                <div className="flex gap-3 flex-1 justify-end">
                    <button onClick={handleSaveDraftLocal} className="flex px-8 py-4 rounded-2xl border border-indigo-100 bg-indigo-50 text-indigo-600 font-black hover:bg-indigo-100 transition-all items-center justify-center gap-3 text-[10px] uppercase tracking-widest active:scale-95 relative overflow-hidden">
                        {showDraftSaved ? (
                            <>
                                <svg className="w-4 h-4 text-emerald-500 animate-bounce" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7"></path></svg>
                                <span className="animate-fadeIn">Draft Saved</span>
                            </>
                        ) : (
                            <>
                                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M19 21H5a2 2 0 01-2-2V5a2 2 0 012-2h11l5 5v11a2 2 0 01-2 2z"></path><polyline points="17 21 17 13 7 13 7 21"></polyline><polyline points="7 3 7 8 15 8"></polyline></svg>
                                Save Draft
                            </>
                        )}
                    </button>
                    {currentSection < SECTIONS.length - 1 && (
                    <button onClick={handleNext} className="flex-1 sm:flex-none px-10 py-4 rounded-2xl bg-slate-900 text-white font-black hover:bg-black shadow-xl transition-all flex items-center justify-center gap-3 text-[10px] uppercase tracking-[0.2em] active:scale-95">
                        Next
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path strokeLinecap="round" strokeLinejoin="round" d="M14 5l7 7m0 0l-7 7m7-7H3"></path></svg>
                    </button>
                    )}
                </div>
              </div>
            </footer>
        </div>
    );
};

export default InspectionFormView;

import React, { useState, useEffect, useMemo } from 'react';
import { INITIAL_DATA, InspectionData, User } from './types';
import { 
    SHEET_HEADERS, PETROLEUM_HEADERS, PETROLEUM_V2_HEADERS, ACID_HEADERS,
    INSPECTION_ITEMS, PETROLEUM_INSPECTION_ITEMS, PETROLEUM_V2_ITEMS, ACID_INSPECTION_ITEMS
} from './constants';

// Hooks
import { useAuth } from './hooks/useAuth';
import { useSettings } from './hooks/useSettings';
import { useNotifications } from './hooks/useNotifications';
import { useHistory } from './hooks/useHistory';
import { useOfflineSync } from './hooks/useOfflineSync';
import { useSubscription } from './hooks/useSubscription';

// Services
import { analyzeInspection } from './services/geminiService';

// UI Components
import Toast from './components/ui/Toast';
import ReportViewerModal from './components/ui/ReportViewerModal';
import SubmissionOverlay from './components/ui/SubmissionOverlay';
import ProfileModal from './components/ui/ProfileModal';
import NotificationCenter from './components/ui/NotificationCenter'; 
import UpgradeModal from './components/ui/UpgradeModal';
import InspectionStartModal from './components/ui/InspectionStartModal';
import SubscriptionAlert from './components/ui/SubscriptionAlert';
import MaintenanceOverlay from './components/ui/MaintenanceOverlay';
import RequestInspectionModal from './components/ui/RequestInspectionModal'; 
import OnboardingWizard from './components/ui/OnboardingWizard'; 
import SystemTour from './components/ui/SystemTour'; 
import InstallPwaPrompt from './components/ui/InstallPwaPrompt';

// Views
import LoginView from './views/LoginView';
import SettingsView from './views/SettingsView';
import GeneralDashboard from './views/GeneralDashboard';
import PetroleumDashboard from './views/PetroleumDashboard';
import PetroleumV2Dashboard from './views/PetroleumV2Dashboard';
import AcidDashboard from './views/AcidDashboard';
import UserManagementView from './views/UserManagementView';
import OverviewDashboard from './views/OverviewDashboard';
import InspectionFormView from './views/InspectionFormView';
import SupportView from './views/SupportView';
import MaintenanceView from './views/MaintenanceView';
import RequestTrackingView from './views/RequestTrackingView';
import AnalyticsDashboard from './views/AnalyticsDashboard';
import FleetWallView from './views/FleetWallView';
import LibraryView from './views/LibraryView';
import FleetRegistryView from './views/FleetRegistryView';

// Report Components
import PrintableGeneralReport from './components/reports/PrintableGeneralReport';
import PrintablePetroleumReport from './components/reports/PrintablePetroleumReport';
import PrintablePetroleumV2Report from './components/reports/PrintablePetroleumV2Report';
import PrintableAcidReport from './components/reports/PrintableAcidReport';

const App = () => {
  const { currentUser, setCurrentUser, handleLogin, handleLogout, sessionExpired, setSessionExpired } = useAuth();
  const { settings, setSettings, appScriptUrl, setAppScriptUrl, isSavingSettings, handleSaveSettings, fetchSystemSettings } = useSettings();
  const { subscription, history: subHistory, refreshSubscription } = useSubscription(appScriptUrl, currentUser);

  const [activeModule, setActiveModule] = useState('overview'); 
  const [viewMode, setViewMode] = useState<'dashboard' | 'form'>('dashboard');
  const [isProfileModalOpen, setIsProfileModalOpen] = useState(false);
  const [toast, setToast] = useState<{message: string, type: 'success' | 'error' | 'info' | 'warning'} | null>(null);
  const [isRequestModalOpen, setIsRequestModalOpen] = useState(false);
  const [showTour, setShowTour] = useState(false);
  const [isCheckingMaint, setIsCheckingMaint] = useState(false);
  const [lastSubmittedData, setLastSubmittedData] = useState<InspectionData | null>(null);
  const [aiAnalysisResult, setAiAnalysisResult] = useState<string | null>(null);

  // Draft Management State
  const [isStartModalOpen, setIsStartModalOpen] = useState(false);
  const [pendingModule, setPendingModule] = useState<string | null>(null);
  const [hasExistingDraft, setHasExistingDraft] = useState(false);

  const { historyList, isLoadingHistory, validationLists, stats, fetchHistory } = useHistory(appScriptUrl, activeModule, currentUser);

  useEffect(() => {
    if (currentUser && !currentUser.needsSetup) {
        setActiveModule('overview');
        setViewMode('dashboard');
    }
  }, [currentUser?.username, currentUser?.needsSetup]);

  const lockInfo = useMemo(() => {
      const isSuperAdmin = currentUser?.role === 'SuperAdmin';
      const isSubExpired = subscription ? (subscription.status === 'Expired' || subscription.daysRemaining <= 0) : false;
      const isMaintActive = settings.maintenanceMode === true;

      if (isSuperAdmin) return { isLocked: false, reason: null as any };

      if (isMaintActive) return { isLocked: true, reason: 'maintenance' as const };
      if (isSubExpired) return { isLocked: true, reason: 'license' as const };

      return { isLocked: false, reason: null as any };
  }, [subscription, settings.maintenanceMode, currentUser?.role]);

  const isSystemLocked = lockInfo.isLocked;

  useEffect(() => {
    (window as any).isSubscriptionLocked = isSystemLocked;
  }, [isSystemLocked]);

  const showToast = (message: string, type: 'success' | 'error' | 'info' | 'warning') => {
      setToast({ message, type });
      setTimeout(() => setToast(null), 4000);
  };

  useEffect(() => {
      if (sessionExpired === 'idle') showToast("Session expired due to inactivity.", 'warning');
      else if (sessionExpired === 'max_duration') showToast("Session limit reached. Log in again.", 'info');
      if (sessionExpired) setSessionExpired(null);
  }, [sessionExpired]);

  const { submissionStatus, setSubmissionStatus, isSyncing, addToQueue } = useOfflineSync(appScriptUrl, showToast, () => fetchHistory(true));

  const handleNavigate = (module: string) => {
    // Check if this is an inspection module that might have a draft
    const inspectionModules = ['general', 'petroleum', 'petroleum_v2', 'acid'];

    if (inspectionModules.includes(module)) {
        const draftKey = `sc_draft_${module}`;
        const draft = localStorage.getItem(draftKey);

        if (draft) {
            setPendingModule(module);
            setHasExistingDraft(true);
            setIsStartModalOpen(true);
            return;
        }

        setActiveModule(module);
        startFreshInspection(module);
        return;
    }

    if (module.startsWith('request:start_inspection')) {
        if (isSystemLocked) {
            showToast("Action Restricted: System is in View-Only mode.", "error");
            return;
        }
        const parts = module.split('|');
        const type = parts[1]?.toLowerCase();
        const truck = parts[2];
        const trailer = parts[3];
        const requester = parts[4];
        const reason = parts[5];
        let moduleKey = 'general';
        if (type === 'petroleum') moduleKey = 'petroleum';
        else if (type === 'petroleum_v2') moduleKey = 'petroleum_v2';
        else if (type === 'acid') moduleKey = 'acid';

        setActiveModule(moduleKey);
        startFreshInspection(moduleKey, {
            truckNo: truck,
            trailerNo: trailer,
            remarks: `Requested by ${requester}: ${reason}`,
            requestId: parts[0].split('-')[1]
        });
        return;
    }
    setActiveModule(module);
    setViewMode('dashboard');
  };

  const { notifications, handleMarkNotificationRead, handleDismissNotification, handleClearAllNotifications, handleGlobalAcknowledge } = useNotifications(appScriptUrl, currentUser, showToast);

  const [isReportModalOpen, setIsReportModalOpen] = useState(false);
  const [selectedReportData, setSelectedReportData] = useState<InspectionData | null>(null);
  const [formInitialData, setFormInitialData] = useState<InspectionData>(INITIAL_DATA);

  const isAdmin = currentUser?.role === 'Admin' || currentUser?.role === 'SuperAdmin';
  const isSuperAdmin = currentUser?.role === 'SuperAdmin';

  const startFreshInspection = (module: string, prefill?: Partial<InspectionData>) => {
      if (isSystemLocked) {
          showToast("RESTRICTED: View-Only mode active.", "error");
          return;
      }
      setLastSubmittedData(null);
      setAiAnalysisResult(null);
      setFormInitialData({ ...INITIAL_DATA, timestamp: new Date().toISOString(), inspectedBy: currentUser?.name || '', ...prefill });
      setViewMode('form');
  };

  const handleResumeDraft = () => {
    if (!pendingModule) return;
    const draftKey = `sc_draft_${pendingModule}`;
    const draftData = localStorage.getItem(draftKey);
    if (draftData) {
        setFormInitialData(JSON.parse(draftData));
        setActiveModule(pendingModule);
        setViewMode('form');
    }
    setIsStartModalOpen(false);
  };

  const handleDiscardAndStartNew = () => {
    if (!pendingModule) return;
    localStorage.removeItem(`sc_draft_${pendingModule}`);
    setActiveModule(pendingModule);
    startFreshInspection(pendingModule);
    setIsStartModalOpen(false);
  };

  const handleSaveDraft = (data: InspectionData) => {
    localStorage.setItem(`sc_draft_${activeModule}`, JSON.stringify(data));
    setViewMode('dashboard');
  };

  const handleExitForm = () => setViewMode('dashboard');

  const handleGoogleSheetSubmit = async (formData: InspectionData) => {
    if (isSystemLocked) {
        showToast("RESTRICTED: View-Only mode. Submission blocked.", "error");
        return;
    }
    if (!appScriptUrl) {
        showToast("Server URL not configured", "error");
        return;
    }

    setSubmissionStatus('submitting');
    setLastSubmittedData(formData);
    setAiAnalysisResult(null);

    let sheetName = 'General';
    let headers = SHEET_HEADERS;
    let moduleTitle = "General Vehicle Inspection";
    let activeItems = INSPECTION_ITEMS;

    if (activeModule === 'petroleum') { 
        sheetName = 'Petroleum'; headers = PETROLEUM_HEADERS; 
        moduleTitle = "Petroleum Tanker Inspection"; activeItems = PETROLEUM_INSPECTION_ITEMS;
    } else if (activeModule === 'petroleum_v2') { 
        sheetName = 'Petroleum_V2'; headers = PETROLEUM_V2_HEADERS; 
        moduleTitle = "Petroleum Tanker Inspection V2"; activeItems = PETROLEUM_V2_ITEMS;
    } else if (activeModule === 'acid') { 
        sheetName = 'Acid'; headers = ACID_HEADERS; 
        moduleTitle = "Acid Tanker Inspection"; activeItems = ACID_INSPECTION_ITEMS;
    }

    const row = headers.map(h => formData[h] !== undefined ? formData[h] : "");
    const reportData = {
        title: moduleTitle,
        timestamp: formData.timestamp,
        truckNo: formData.truckNo,
        trailerNo: formData.trailerNo,
        jobCard: formData.jobCard,
        location: formData.location,
        odometer: formData.odometer,
        inspectedBy: formData.inspectedBy,
        driverName: formData.driverName,
        remarks: formData.remarks,
        rate: formData.rate,
        signatures: { inspector: formData.inspectorSignature, driver: formData.driverSignature },
        photos: { front: formData.photoFront, ls: formData.photoLS, rs: formData.photoRS, back: formData.photoBack, damage: formData.photoDamage },
        items: activeItems.map(item => ({ label: item.label, category: item.category, status: formData[item.id] || 'N/A' })),
        companyName: settings.companyName,
        companyLogo: settings.companyLogo
    };

    const payload = { action: 'create', sheet: sheetName, headers: headers, row: row, requestId: formData.requestId || null, reportData: reportData };

    if (!navigator.onLine) {
        addToQueue(payload);
        // Clear draft on success/queue
        localStorage.removeItem(`sc_draft_${activeModule}`);
        setSubmissionStatus('offline_saved');
        setTimeout(() => { setSubmissionStatus('idle'); setViewMode('dashboard'); }, 3500);
        return;
    }

    try {
        await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify(payload), mode: 'no-cors' });
        setSubmissionStatus('success');

        // Clear draft on success
        localStorage.removeItem(`sc_draft_${activeModule}`);

        // Trigger AI Analysis
        try {
            const analysis = await analyzeInspection(formData);
            setAiAnalysisResult(analysis);
        } catch (aiErr) {
            setAiAnalysisResult("AI analysis skipped due to connectivity or processing error.");
        }

        fetchHistory(true); 
    } catch (error) {
        console.error("Submission error", error);
        addToQueue(payload);
        localStorage.removeItem(`sc_draft_${activeModule}`);
        setSubmissionStatus('offline_saved');
        setTimeout(() => { setSubmissionStatus('idle'); setViewMode('dashboard'); }, 3500);
    }
  };

  const handleRequestSubmit = async (data: any) => {
      if (isSystemLocked) { showToast("RESTRICTED: View-Only mode. Requests disabled.", "error"); return; }
      if (!appScriptUrl) return;
      try {
          await fetch(appScriptUrl, {
              method: 'POST',
              body: JSON.stringify({ action: 'request_inspection', requester: currentUser?.name, role: currentUser?.role, ...data }),
              mode: 'no-cors'
          });
          showToast("Inspection Request submitted successfully", "success");
      } catch (e) { showToast("Failed to submit request", "error"); }
  };

  const handleViewReport = (item: InspectionData | null) => {
    setSelectedReportData(item);
    setIsReportModalOpen(true);
  };

  const handleOnboardingComplete = (updatedUser: User) => {
      const userWithSetup = { ...updatedUser, needsSetup: false };
      setCurrentUser(userWithSetup);
      localStorage.setItem('safetyCheck_user', JSON.stringify(userWithSetup));
      setActiveModule('overview');
      setViewMode('dashboard');
      showToast("Identity verified. Welcome aboard!", "success");
      setShowTour(true);
  };

  const handleCheckMaintStatus = async () => {
    setIsCheckingMaint(true);
    try { await fetchSystemSettings(appScriptUrl, true); showToast("System status updated.", "info"); } finally { setIsCheckingMaint(false); }
  };

  const isAtRoot = activeModule === 'overview';

  if (!currentUser) {
      return (
          <>
            <InstallPwaPrompt />
            {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
            <LoginView onLogin={handleLogin} appScriptUrl={appScriptUrl} setAppScriptUrl={setAppScriptUrl} settings={settings} />
          </>
      );
  }

  if (currentUser && currentUser.needsSetup) {
      return <OnboardingWizard user={currentUser} appScriptUrl={appScriptUrl} onComplete={handleOnboardingComplete} />;
  }

  return (
    <div className="min-h-screen bg-white font-sans text-gray-900 relative">
      <SubmissionOverlay 
        status={submissionStatus} 
        onClose={() => { setSubmissionStatus('idle'); setViewMode('dashboard'); }}
        onViewReport={() => lastSubmittedData && handleViewReport(lastSubmittedData)}
        aiAnalysis={aiAnalysisResult}
      />
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
      {showTour && <SystemTour onComplete={() => setShowTour(false)} />}

      {isProfileModalOpen && (
          <ProfileModal user={currentUser} settings={settings} appScriptUrl={appScriptUrl} onClose={() => setIsProfileModalOpen(false)} showToast={showToast} onUpdateSuccess={(u) => setCurrentUser(u)} onLogout={() => { setIsProfileModalOpen(false); handleLogout(); }} />
      )}

      <RequestInspectionModal isOpen={isRequestModalOpen} onClose={() => setIsRequestModalOpen(false)} onSubmit={handleRequestSubmit} validationLists={validationLists} currentUserRole={currentUser.role} />

      <InspectionStartModal 
        isOpen={isStartModalOpen} 
        onClose={() => setIsStartModalOpen(false)} 
        onStartNew={handleDiscardAndStartNew} 
        onResume={handleResumeDraft} 
        hasDraft={hasExistingDraft} 
        moduleName={pendingModule || ''} 
      />

      <div className="relative z-10 min-h-screen flex flex-col">
          <div className="no-print">
            {settings.maintenanceMode && (
                <div className="bg-amber-600 px-4 py-3 flex flex-col sm:flex-row items-center justify-center gap-2 sm:gap-6 text-white shadow-lg relative z-[101]">
                    <div className="flex items-center gap-3">
                        <div className="w-8 h-8 bg-white/20 rounded-full flex items-center justify-center animate-pulse">
                            <svg className="w-5 h-5 text-amber-100" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z"></path></svg>
                        </div>
                        <div className="text-center sm:text-left">
                            <p className="text-[10px] font-black uppercase tracking-[0.2em] mb-1">System Maintenance Mode Active</p>
                            <p className="text-[11px] font-medium text-amber-5 text-amber-50 leading-tight">{settings.maintenanceMessage || 'Restricted view-only mode enabled.'}</p>
                        </div>
                    </div>
                    <button onClick={handleCheckMaintStatus} disabled={isCheckingMaint} className="px-4 py-1.5 bg-white/10 hover:bg-white/20 border border-white/30 rounded-lg text-[9px] font-black uppercase tracking-widest transition-all flex items-center gap-2">
                        {isCheckingMaint ? <svg className="animate-spin h-3 w-3" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg> : null}
                        {isCheckingMaint ? 'Checking...' : 'Check Status'}
                    </button>
                </div>
            )}
            <SubscriptionAlert subscription={subscription} user={currentUser} onManage={() => setActiveModule('maintenance')} />
          </div>

          <header className="bg-white border-b border-gray-100 sticky top-0 z-40 px-4 py-2 flex items-center justify-between h-14 no-print">
              <div className="flex items-center gap-1 sm:gap-2">
                  {!isAtRoot ? (
                      <button onClick={() => { setActiveModule('overview'); setViewMode('dashboard'); }} title="Back to Overview" className="p-2 text-slate-900 hover:bg-slate-50 rounded-lg transition-all flex items-center group">
                          <svg className="w-5 h-5 transition-transform group-hover:-translate-x-0.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M15 19l-7-7 7-7"></path></svg>
                          <span className="text-[10px] font-bold uppercase tracking-widest ml-1 hidden sm:inline">Back</span>
                      </button>
                  ) : <div className="w-10"></div>}
              </div>
              <button onClick={() => { setActiveModule('overview'); setViewMode('dashboard'); }} className="flex flex-col items-center hover:opacity-70 transition-opacity">
                  <h1 className="text-lg font-bold text-slate-900 tracking-tight leading-none uppercase">{settings.companyName || 'SafetyCheck Pro'}</h1>
                  <span className="text-[7px] font-bold text-slate-400 tracking-[0.3em] mt-1 uppercase">Fleet Portal</span>
              </button>
              <div className="flex items-center gap-1">
                  <NotificationCenter id="notification-bell" notifications={notifications} onMarkAsRead={(id) => handleMarkNotificationRead(id, handleNavigate)} onDismiss={handleDismissNotification} onClearAll={handleClearAllNotifications} onAcknowledge={handleGlobalAcknowledge} canAcknowledge={isAdmin} />
                  <button onClick={() => setIsProfileModalOpen(true)} className={`p-2 transition-colors ${isProfileModalOpen ? 'text-slate-900 bg-slate-50 rounded-full' : 'text-slate-400 hover:text-slate-600'}`}>
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z"></path></svg>
                  </button>
              </div>
          </header>

          {isSystemLocked && (
              <div className="bg-amber-100 border-b border-amber-200 px-4 py-2 flex items-center justify-center gap-3 animate-pulse no-print">
                  <svg className="w-4 h-4 text-amber-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z"></path></svg>
                  <span className="text-[10px] font-black text-amber-800 uppercase tracking-widest">
                      {lockInfo.reason === 'maintenance' ? 'System in Maintenance Mode' : 'View-Only Mode - License Expired'}
                  </span>
              </div>
          )}

          <main className="flex-1 p-4 md:p-8 w-full max-w-7xl mx-auto no-print">
              {viewMode === 'form' ? (
                  <InspectionFormView initialData={formInitialData} activeModule={activeModule} validationLists={validationLists} settings={settings} onSaveDraft={handleSaveDraft} onExit={handleExitForm} onSubmit={handleGoogleSheetSubmit} submissionStatus={submissionStatus} onViewReport={handleViewReport} />
              ) : (
                  <div className="animate-fadeIn">
                      {activeModule === 'overview' && <OverviewDashboard appScriptUrl={appScriptUrl} onNavigate={handleNavigate} userRole={currentUser.role} historyList={historyList} isLoading={isLoadingHistory} onViewReport={handleViewReport} isMaintenanceActive={settings.maintenanceMode} pendingAlertsCount={notifications.filter(n => !n.read && n.type === 'critical').length} isLocked={isSystemLocked} />}
                      {activeModule === 'analytics' && <AnalyticsDashboard historyList={historyList} isLoading={isLoadingHistory} />}
                      {activeModule === 'fleet_wall' && <FleetWallView historyList={historyList} isLoading={isLoadingHistory} onClose={() => handleNavigate('overview')} />}
                      {activeModule === 'library' && <LibraryView />}
                      {(activeModule === 'settings' && isAdmin) && <SettingsView settings={settings} setSettings={setSettings} appScriptUrl={appScriptUrl} setAppScriptUrl={setAppScriptUrl} handleSaveSettings={handleSaveSettings} isSavingSettings={isSavingSettings} showToast={showToast} user={currentUser} />}
                      {(activeModule === 'maintenance' && isSuperAdmin) && <MaintenanceView user={currentUser} appScriptUrl={appScriptUrl} settings={settings} onSettingsUpdate={(s) => setSettings(p => ({...p, ...s}))} showToast={showToast} onRefreshSubscription={refreshSubscription} subscription={subscription} history={subHistory} />}
                      {activeModule === 'general' && <GeneralDashboard userRole={currentUser.role} stats={stats} startNewInspection={() => handleNavigate('general')} fetchHistory={fetchHistory} isLoadingHistory={isLoadingHistory} historyList={historyList} onViewReport={handleViewReport} onPrint={() => {}} isLocked={isSystemLocked} lockReason={lockInfo.reason} maintenanceMessage={settings.maintenanceMessage} />}
                      {activeModule === 'petroleum' && <PetroleumDashboard userRole={currentUser.role} stats={stats} startNewInspection={() => handleNavigate('petroleum')} fetchHistory={fetchHistory} isLoadingHistory={isLoadingHistory} historyList={historyList} onViewReport={handleViewReport} onPrint={() => {}} isLocked={isSystemLocked} lockReason={lockInfo.reason} maintenanceMessage={settings.maintenanceMessage} />}
                      {activeModule === 'petroleum_v2' && <PetroleumV2Dashboard userRole={currentUser.role} stats={stats} startNewInspection={() => handleNavigate('petroleum_v2')} fetchHistory={fetchHistory} isLoadingHistory={isLoadingHistory} historyList={historyList} onViewReport={handleViewReport} onPrint={() => {}} isLocked={isSystemLocked} lockReason={lockInfo.reason} maintenanceMessage={settings.maintenanceMessage} />}
                      {activeModule === 'acid' && <AcidDashboard userRole={currentUser.role} stats={stats} startNewInspection={() => handleNavigate('acid')} fetchHistory={fetchHistory} isLoadingHistory={isLoadingHistory} historyList={historyList} onViewReport={handleViewReport} onPrint={() => {}} isLocked={isSystemLocked} lockReason={lockInfo.reason} maintenanceMessage={settings.maintenanceMessage} />}
                      {(activeModule === 'users' && isAdmin) && <UserManagementView currentUser={currentUser} appScriptUrl={appScriptUrl} showToast={showToast} validationLists={validationLists} settings={settings} />}
                      {activeModule === 'support' && <SupportView appScriptUrl={appScriptUrl} currentUser={currentUser} showToast={showToast} settings={settings} validationLists={validationLists} />}
                      {activeModule === 'track_requests' && <RequestTrackingView appScriptUrl={appScriptUrl} currentUser={currentUser} showToast={showToast} onRequestNew={() => setIsRequestModalOpen(true)} />}
                      {activeModule === 'registry' && <FleetRegistryView appScriptUrl={appScriptUrl} validationLists={validationLists} onRefresh={() => fetchHistory(true)} showToast={showToast} isLocked={isSystemLocked} />}
                  </div>
              )}
          </main>
          <footer className="mt-auto py-6 border-t border-slate-50 text-center no-print">
              <span className="text-[9px] font-bold text-slate-300 uppercase tracking-[0.2em]">scbc@2026</span>
          </footer>
      </div>

      {isReportModalOpen && selectedReportData && (
          <ReportViewerModal onClose={() => setIsReportModalOpen(false)} onPrint={() => window.print()} title={`Report_${selectedReportData.id || 'History'}`}>
              {activeModule === 'petroleum' ? <PrintablePetroleumReport data={selectedReportData} settings={settings} /> : activeModule === 'petroleum_v2' ? <PrintablePetroleumV2Report data={selectedReportData} settings={settings} /> : activeModule === 'acid' ? <PrintableAcidReport data={selectedReportData} settings={settings} /> : <PrintableGeneralReport data={selectedReportData} settings={settings} />}
          </ReportViewerModal>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { INITIAL_DATA, InspectionData, User } from './types';
import { 
    SHEET_HEADERS, PETROLEUM_HEADERS, PETROLEUM_V2_HEADERS, ACID_HEADERS,
    INSPECTION_ITEMS, PETROLEUM_INSPECTION_ITEMS, PETROLEUM_V2_ITEMS, ACID_INSPECTION_ITEMS
} from './constants';

// Hooks
import { useAuth } from './hooks/useAuth';
import { useSettings } from './hooks/useSettings';
import { useNotifications } from './hooks/useNotifications';
import { useHistory } from './hooks/useHistory';
import { useOfflineSync } from './hooks/useOfflineSync';
import { useSubscription } from './hooks/useSubscription';

// Services
import { analyzeInspection } from './services/geminiService';

// UI Components
import Toast from './components/ui/Toast';
import ReportViewerModal from './components/ui/ReportViewerModal';
import SubmissionOverlay from './components/ui/SubmissionOverlay';
import ProfileModal from './components/ui/ProfileModal';
import NotificationCenter from './components/ui/NotificationCenter'; 
import UpgradeModal from './components/ui/UpgradeModal';
import InspectionStartModal from './components/ui/InspectionStartModal';
import SubscriptionAlert from './components/ui/SubscriptionAlert';
import MaintenanceOverlay from './components/ui/MaintenanceOverlay';
import RequestInspectionModal from './components/ui/RequestInspectionModal'; 
import OnboardingWizard from './components/ui/OnboardingWizard'; 
import SystemTour from './components/ui/SystemTour'; 
import InstallPwaPrompt from './components/ui/InstallPwaPrompt';

// Views
import LoginView from './views/LoginView';
import SettingsView from './views/SettingsView';
import GeneralDashboard from './views/GeneralDashboard';
import PetroleumDashboard from './views/PetroleumDashboard';
import PetroleumV2Dashboard from './views/PetroleumV2Dashboard';
import AcidDashboard from './views/AcidDashboard';
import UserManagementView from './views/UserManagementView';
import OverviewDashboard from './views/OverviewDashboard';
import InspectionFormView from './views/InspectionFormView';
import SupportView from './views/SupportView';
import MaintenanceView from './views/MaintenanceView';
import RequestTrackingView from './views/RequestTrackingView';
import AnalyticsDashboard from './views/AnalyticsDashboard';
import FleetWallView from './views/FleetWallView';
import LibraryView from './views/LibraryView';
import FleetRegistryView from './views/FleetRegistryView';

// Report Components
import PrintableGeneralReport from './components/reports/PrintableGeneralReport';
import PrintablePetroleumReport from './components/reports/PrintablePetroleumReport';
import PrintablePetroleumV2Report from './components/reports/PrintablePetroleumV2Report';
import PrintableAcidReport from './components/reports/PrintableAcidReport';

const App = () => {
  const { currentUser, setCurrentUser, handleLogin, handleLogout, sessionExpired, setSessionExpired } = useAuth();
  const { settings, setSettings, appScriptUrl, setAppScriptUrl, isSavingSettings, handleSaveSettings, fetchSystemSettings } = useSettings();
  const { subscription, history: subHistory, refreshSubscription } = useSubscription(appScriptUrl, currentUser);

  const [activeModule, setActiveModule] = useState('overview'); 
  const [viewMode, setViewMode] = useState<'dashboard' | 'form'>('dashboard');
  const [isProfileModalOpen, setIsProfileModalOpen] = useState(false);
  const [toast, setToast] = useState<{message: string, type: 'success' | 'error' | 'info' | 'warning'} | null>(null);
  const [isRequestModalOpen, setIsRequestModalOpen] = useState(false);
  const [showTour, setShowTour] = useState(false);
  const [isCheckingMaint, setIsCheckingMaint] = useState(false);
  const [lastSubmittedData, setLastSubmittedData] = useState<InspectionData | null>(null);
  const [aiAnalysisResult, setAiAnalysisResult] = useState<string | null>(null);

  // Draft Management State
  const [isStartModalOpen, setIsStartModalOpen] = useState(false);
  const [pendingModule, setPendingModule] = useState<string | null>(null);
  const [hasExistingDraft, setHasExistingDraft] = useState(false);

  const { historyList, isLoadingHistory, validationLists, stats, fetchHistory } = useHistory(appScriptUrl, activeModule, currentUser);

  useEffect(() => {
    if (currentUser && !currentUser.needsSetup) {
        setActiveModule('overview');
        setViewMode('dashboard');
    }
  }, [currentUser?.username, currentUser?.needsSetup]);

  const lockInfo = useMemo(() => {
      const isSuperAdmin = currentUser?.role === 'SuperAdmin';
      const isSubExpired = subscription ? (subscription.status === 'Expired' || subscription.daysRemaining <= 0) : false;
      const isMaintActive = settings.maintenanceMode === true;

      if (isSuperAdmin) return { isLocked: false, reason: null as any };

      if (isMaintActive) return { isLocked: true, reason: 'maintenance' as const };
      if (isSubExpired) return { isLocked: true, reason: 'license' as const };

      return { isLocked: false, reason: null as any };
  }, [subscription, settings.maintenanceMode, currentUser?.role]);

  const isSystemLocked = lockInfo.isLocked;

  useEffect(() => {
    (window as any).isSubscriptionLocked = isSystemLocked;
  }, [isSystemLocked]);

  const showToast = (message: string, type: 'success' | 'error' | 'info' | 'warning') => {
      setToast({ message, type });
      setTimeout(() => setToast(null), 4000);
  };

  useEffect(() => {
      if (sessionExpired === 'idle') showToast("Session expired due to inactivity.", 'warning');
      else if (sessionExpired === 'max_duration') showToast("Session limit reached. Log in again.", 'info');
      if (sessionExpired) setSessionExpired(null);
  }, [sessionExpired]);

  const { submissionStatus, setSubmissionStatus, isSyncing, addToQueue } = useOfflineSync(appScriptUrl, showToast, () => fetchHistory(true));

  // FIX: handleNavigate now strictly handles VIEW navigation
  const handleNavigate = (module: string) => {
    if (module.startsWith('request:start_inspection')) {
        if (isSystemLocked) {
            showToast("Action Restricted: System is in View-Only mode.", "error");
            return;
        }
        const parts = module.split('|');
        const type = parts[1]?.toLowerCase();
        const truck = parts[2];
        const trailer = parts[3];
        const requester = parts[4];
        const reason = parts[5];
        let moduleKey = 'general';
        if (type === 'petroleum') moduleKey = 'petroleum';
        else if (type === 'petroleum_v2') moduleKey = 'petroleum_v2';
        else if (type === 'acid') moduleKey = 'acid';

        setActiveModule(moduleKey);
        startFreshInspection(moduleKey, {
            truckNo: truck,
            trailerNo: trailer,
            remarks: `Requested by ${requester}: ${reason}`,
            requestId: parts[0].split('-')[1]
        });
        return;
    }

    setActiveModule(module);
    setViewMode('dashboard');
  };

  // NEW: Logical handler for initiating a new inspection (checks for drafts)
  const handleOpenInspectionFlow = (module: string) => {
    if (isSystemLocked) {
        showToast("Action Restricted: System is in View-Only mode.", "error");
        return;
    }
    const draftKey = `sc_draft_${module}`;
    const draft = localStorage.getItem(draftKey);

    if (draft) {
        setPendingModule(module);
        setHasExistingDraft(true);
        setIsStartModalOpen(true);
    } else {
        startFreshInspection(module);
    }
  };

  const { notifications, handleMarkNotificationRead, handleDismissNotification, handleClearAllNotifications, handleGlobalAcknowledge } = useNotifications(appScriptUrl, currentUser, showToast);

  const [isReportModalOpen, setIsReportModalOpen] = useState(false);
  const [selectedReportData, setSelectedReportData] = useState<InspectionData | null>(null);
  const [formInitialData, setFormInitialData] = useState<InspectionData>(INITIAL_DATA);

  const isAdmin = currentUser?.role === 'Admin' || currentUser?.role === 'SuperAdmin';
  const isSuperAdmin = currentUser?.role === 'SuperAdmin';

  const startFreshInspection = (module: string, prefill?: Partial<InspectionData>) => {
      if (isSystemLocked) {
          showToast("RESTRICTED: View-Only mode active.", "error");
          return;
      }
      setLastSubmittedData(null);
      setAiAnalysisResult(null);
      setFormInitialData({ ...INITIAL_DATA, timestamp: new Date().toISOString(), inspectedBy: currentUser?.name || '', ...prefill });
      setViewMode('form');
  };

  const handleResumeDraft = () => {
    if (!pendingModule) return;
    const draftKey = `sc_draft_${pendingModule}`;
    const draftData = localStorage.getItem(draftKey);
    if (draftData) {
        setFormInitialData(JSON.parse(draftData));
        setActiveModule(pendingModule);
        setViewMode('form');
    }
    setIsStartModalOpen(false);
  };

  const handleDiscardAndStartNew = () => {
    if (!pendingModule) return;
    localStorage.removeItem(`sc_draft_${pendingModule}`);
    setActiveModule(pendingModule);
    startFreshInspection(pendingModule);
    setIsStartModalOpen(false);
  };

  const handleSaveDraft = (data: InspectionData) => {
    localStorage.setItem(`sc_draft_${activeModule}`, JSON.stringify(data));
    setViewMode('dashboard');
  };

  const handleExitForm = () => setViewMode('dashboard');

  const handleGoogleSheetSubmit = async (formData: InspectionData) => {
    if (isSystemLocked) {
        showToast("RESTRICTED: View-Only mode. Submission blocked.", "error");
        return;
    }
    if (!appScriptUrl) {
        showToast("Server URL not configured", "error");
        return;
    }

    setSubmissionStatus('submitting');
    setLastSubmittedData(formData);
    setAiAnalysisResult(null);

    let sheetName = 'General';
    let headers = SHEET_HEADERS;
    let moduleTitle = "General Vehicle Inspection";
    let activeItems = INSPECTION_ITEMS;

    if (activeModule === 'petroleum') { 
        sheetName = 'Petroleum'; headers = PETROLEUM_HEADERS; 
        moduleTitle = "Petroleum Tanker Inspection"; activeItems = PETROLEUM_INSPECTION_ITEMS;
    } else if (activeModule === 'petroleum_v2') { 
        sheetName = 'Petroleum_V2'; headers = PETROLEUM_V2_HEADERS; 
        moduleTitle = "Petroleum Tanker Inspection V2"; activeItems = PETROLEUM_V2_ITEMS;
    } else if (activeModule === 'acid') { 
        sheetName = 'Acid'; headers = ACID_HEADERS; 
        moduleTitle = "Acid Tanker Inspection"; activeItems = ACID_INSPECTION_ITEMS;
    }

    const row = headers.map(h => formData[h] !== undefined ? formData[h] : "");
    const reportData = {
        title: moduleTitle,
        timestamp: formData.timestamp,
        truckNo: formData.truckNo,
        trailerNo: formData.trailerNo,
        jobCard: formData.jobCard,
        location: formData.location,
        odometer: formData.odometer,
        inspectedBy: formData.inspectedBy,
        driverName: formData.driverName,
        remarks: formData.remarks,
        rate: formData.rate,
        signatures: { inspector: formData.inspectorSignature, driver: formData.driverSignature },
        photos: { front: formData.photoFront, ls: formData.photoLS, rs: formData.photoRS, back: formData.photoBack, damage: formData.photoDamage },
        items: activeItems.map(item => ({ label: item.label, category: item.category, status: formData[item.id] || 'N/A' })),
        companyName: settings.companyName,
        companyLogo: settings.companyLogo
    };

    const payload = { action: 'create', sheet: sheetName, headers: headers, row: row, requestId: formData.requestId || null, reportData: reportData };

    if (!navigator.onLine) {
        addToQueue(payload);
        localStorage.removeItem(`sc_draft_${activeModule}`);
        setSubmissionStatus('offline_saved');
        setTimeout(() => { setSubmissionStatus('idle'); setViewMode('dashboard'); }, 3500);
        return;
    }

    try {
        await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify(payload), mode: 'no-cors' });
        setSubmissionStatus('success');
        localStorage.removeItem(`sc_draft_${activeModule}`);
        try {
            const analysis = await analyzeInspection(formData);
            setAiAnalysisResult(analysis);
        } catch (aiErr) {
            setAiAnalysisResult("AI analysis skipped due to connectivity or processing error.");
        }
        fetchHistory(true); 
    } catch (error) {
        console.error("Submission error", error);
        addToQueue(payload);
        localStorage.removeItem(`sc_draft_${activeModule}`);
        setSubmissionStatus('offline_saved');
        setTimeout(() => { setSubmissionStatus('idle'); setViewMode('dashboard'); }, 3500);
    }
  };

  const handleRequestSubmit = async (data: any) => {
      if (isSystemLocked) { showToast("RESTRICTED: View-Only mode. Requests disabled.", "error"); return; }
      if (!appScriptUrl) return;
      try {
          await fetch(appScriptUrl, {
              method: 'POST',
              body: JSON.stringify({ action: 'request_inspection', requester: currentUser?.name, role: currentUser?.role, ...data }),
              mode: 'no-cors'
          });
          showToast("Inspection Request submitted successfully", "success");
      } catch (e) { showToast("Failed to submit request", "error"); }
  };

  const handleViewReport = (item: InspectionData | null) => {
    setSelectedReportData(item);
    setIsReportModalOpen(true);
  };

  const handleOnboardingComplete = (updatedUser: User) => {
      const userWithSetup = { ...updatedUser, needsSetup: false };
      setCurrentUser(userWithSetup);
      localStorage.setItem('safetyCheck_user', JSON.stringify(userWithSetup));
      setActiveModule('overview');
      setViewMode('dashboard');
      showToast("Identity verified. Welcome aboard!", "success");
      setShowTour(true);
  };

  const handleCheckMaintStatus = async () => {
    setIsCheckingMaint(true);
    try { await fetchSystemSettings(appScriptUrl, true); showToast("System status updated.", "info"); } finally { setIsCheckingMaint(false); }
  };

  const isAtRoot = activeModule === 'overview';

  if (!currentUser) {
      return (
          <>
            <InstallPwaPrompt />
            {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
            <LoginView onLogin={handleLogin} appScriptUrl={appScriptUrl} setAppScriptUrl={setAppScriptUrl} settings={settings} />
          </>
      );
  }

  if (currentUser && currentUser.needsSetup) {
      return <OnboardingWizard user={currentUser} appScriptUrl={appScriptUrl} onComplete={handleOnboardingComplete} />;
  }

  return (
    <div className="min-h-screen bg-white font-sans text-gray-900 relative">
      <SubmissionOverlay 
        status={submissionStatus} 
        onClose={() => { setSubmissionStatus('idle'); setViewMode('dashboard'); }}
        onViewReport={() => lastSubmittedData && handleViewReport(lastSubmittedData)}
        aiAnalysis={aiAnalysisResult}
      />
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
      {showTour && <SystemTour onComplete={() => setShowTour(false)} />}

      {isProfileModalOpen && (
          <ProfileModal user={currentUser} settings={settings} appScriptUrl={appScriptUrl} onClose={() => setIsProfileModalOpen(false)} showToast={showToast} onUpdateSuccess={(u) => setCurrentUser(u)} onLogout={() => { setIsProfileModalOpen(false); handleLogout(); }} />
      )}

      <RequestInspectionModal isOpen={isRequestModalOpen} onClose={() => setIsRequestModalOpen(false)} onSubmit={handleRequestSubmit} validationLists={validationLists} currentUserRole={currentUser.role} />

      <InspectionStartModal 
        isOpen={isStartModalOpen} 
        onClose={() => setIsStartModalOpen(false)} 
        onStartNew={handleDiscardAndStartNew} 
        onResume={handleResumeDraft} 
        hasDraft={hasExistingDraft} 
        moduleName={pendingModule || ''} 
      />

      <div className="relative z-10 min-h-screen flex flex-col">
          <div className="no-print">
            {settings.maintenanceMode && (
                <div className="bg-amber-600 px-4 py-3 flex flex-col sm:flex-row items-center justify-center gap-2 sm:gap-6 text-white shadow-lg relative z-[101]">
                    <div className="flex items-center gap-3">
                        <div className="w-8 h-8 bg-white/20 rounded-full flex items-center justify-center animate-pulse">
                            <svg className="w-5 h-5 text-amber-100" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z"></path></svg>
                        </div>
                        <div className="text-center sm:text-left">
                            <p className="text-[10px] font-black uppercase tracking-[0.2em] mb-1">System Maintenance Mode Active</p>
                            <p className="text-[11px] font-medium text-amber-5 text-amber-50 leading-tight">{settings.maintenanceMessage || 'Restricted view-only mode enabled.'}</p>
                        </div>
                    </div>
                    <button onClick={handleCheckMaintStatus} disabled={isCheckingMaint} className="px-4 py-1.5 bg-white/10 hover:bg-white/20 border border-white/30 rounded-lg text-[9px] font-black uppercase tracking-widest transition-all flex items-center gap-2">
                        {isCheckingMaint ? <svg className="animate-spin h-3 w-3" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg> : null}
                        {isCheckingMaint ? 'Checking...' : 'Check Status'}
                    </button>
                </div>
            )}
            <SubscriptionAlert subscription={subscription} user={currentUser} onManage={() => setActiveModule('maintenance')} />
          </div>

          <header className="bg-white border-b border-gray-100 sticky top-0 z-40 px-4 py-2 flex items-center justify-between h-14 no-print">
              <div className="flex items-center gap-1 sm:gap-2">
                  {!isAtRoot ? (
                      <button onClick={() => { setActiveModule('overview'); setViewMode('dashboard'); }} title="Back to Overview" className="p-2 text-slate-900 hover:bg-slate-50 rounded-lg transition-all flex items-center group">
                          <svg className="w-5 h-5 transition-transform group-hover:-translate-x-0.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M15 19l-7-7 7-7"></path></svg>
                          <span className="text-[10px] font-bold uppercase tracking-widest ml-1 hidden sm:inline">Back</span>
                      </button>
                  ) : <div className="w-10"></div>}
              </div>
              <button onClick={() => { setActiveModule('overview'); setViewMode('dashboard'); }} className="flex flex-col items-center hover:opacity-70 transition-opacity">
                  <h1 className="text-lg font-bold text-slate-900 tracking-tight leading-none uppercase">{settings.companyName || 'SafetyCheck Pro'}</h1>
                  <span className="text-[7px] font-bold text-slate-400 tracking-[0.3em] mt-1 uppercase">Fleet Portal</span>
              </button>
              <div className="flex items-center gap-1">
                  <NotificationCenter id="notification-bell" notifications={notifications} onMarkAsRead={(id) => handleMarkNotificationRead(id, handleNavigate)} onDismiss={handleDismissNotification} onClearAll={handleClearAllNotifications} onAcknowledge={handleGlobalAcknowledge} canAcknowledge={isAdmin} />
                  <button onClick={() => setIsProfileModalOpen(true)} className={`p-2 transition-colors ${isProfileModalOpen ? 'text-slate-900 bg-slate-50 rounded-full' : 'text-slate-400 hover:text-slate-600'}`}>
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z"></path></svg>
                  </button>
              </div>
          </header>

          {isSystemLocked && (
              <div className="bg-amber-100 border-b border-amber-200 px-4 py-2 flex items-center justify-center gap-3 animate-pulse no-print">
                  <svg className="w-4 h-4 text-amber-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z"></path></svg>
                  <span className="text-[10px] font-black text-amber-800 uppercase tracking-widest">
                      {lockInfo.reason === 'maintenance' ? 'System in Maintenance Mode' : 'View-Only Mode - License Expired'}
                  </span>
              </div>
          )}

          <main className="flex-1 p-4 md:p-8 w-full max-w-7xl mx-auto no-print">
              {viewMode === 'form' ? (
                  <InspectionFormView initialData={formInitialData} activeModule={activeModule} validationLists={validationLists} settings={settings} onSaveDraft={handleSaveDraft} onExit={handleExitForm} onSubmit={handleGoogleSheetSubmit} submissionStatus={submissionStatus} onViewReport={handleViewReport} />
              ) : (
                  <div className="animate-fadeIn">
                      {activeModule === 'overview' && <OverviewDashboard appScriptUrl={appScriptUrl} onNavigate={handleNavigate} userRole={currentUser.role} historyList={historyList} isLoading={isLoadingHistory} onViewReport={handleViewReport} isMaintenanceActive={settings.maintenanceMode} pendingAlertsCount={notifications.filter(n => !n.read && n.type === 'critical').length} isLocked={isSystemLocked} />}
                      {activeModule === 'analytics' && <AnalyticsDashboard historyList={historyList} isLoading={isLoadingHistory} />}
                      {activeModule === 'fleet_wall' && <FleetWallView historyList={historyList} isLoading={isLoadingHistory} onClose={() => handleNavigate('overview')} />}
                      {activeModule === 'library' && <LibraryView />}
                      {(activeModule === 'settings' && isAdmin) && <SettingsView settings={settings} setSettings={setSettings} appScriptUrl={appScriptUrl} setAppScriptUrl={setAppScriptUrl} handleSaveSettings={handleSaveSettings} isSavingSettings={isSavingSettings} showToast={showToast} user={currentUser} />}
                      {(activeModule === 'maintenance' && isSuperAdmin) && <MaintenanceView user={currentUser} appScriptUrl={appScriptUrl} settings={settings} onSettingsUpdate={(s) => setSettings(p => ({...p, ...s}))} showToast={showToast} onRefreshSubscription={refreshSubscription} subscription={subscription} history={subHistory} />}
                      {activeModule === 'general' && <GeneralDashboard userRole={currentUser.role} stats={stats} startNewInspection={() => handleOpenInspectionFlow('general')} fetchHistory={fetchHistory} isLoadingHistory={isLoadingHistory} historyList={historyList} onViewReport={handleViewReport} onPrint={() => {}} isLocked={isSystemLocked} lockReason={lockInfo.reason} maintenanceMessage={settings.maintenanceMessage} />}
                      {activeModule === 'petroleum' && <PetroleumDashboard userRole={currentUser.role} stats={stats} startNewInspection={() => handleOpenInspectionFlow('petroleum')} fetchHistory={fetchHistory} isLoadingHistory={isLoadingHistory} historyList={historyList} onViewReport={handleViewReport} onPrint={() => {}} isLocked={isSystemLocked} lockReason={lockInfo.reason} maintenanceMessage={settings.maintenanceMessage} />}
                      {activeModule === 'petroleum_v2' && <PetroleumV2Dashboard userRole={currentUser.role} stats={stats} startNewInspection={() => handleOpenInspectionFlow('petroleum_v2')} fetchHistory={fetchHistory} isLoadingHistory={isLoadingHistory} historyList={historyList} onViewReport={handleViewReport} onPrint={() => {}} isLocked={isSystemLocked} lockReason={lockInfo.reason} maintenanceMessage={settings.maintenanceMessage} />}
                      {activeModule === 'acid' && <AcidDashboard userRole={currentUser.role} stats={stats} startNewInspection={() => handleOpenInspectionFlow('acid')} fetchHistory={fetchHistory} isLoadingHistory={isLoadingHistory} historyList={historyList} onViewReport={handleViewReport} onPrint={() => {}} isLocked={isSystemLocked} lockReason={lockInfo.reason} maintenanceMessage={settings.maintenanceMessage} />}
                      {(activeModule === 'users' && isAdmin) && <UserManagementView currentUser={currentUser} appScriptUrl={appScriptUrl} showToast={showToast} validationLists={validationLists} settings={settings} />}
                      {activeModule === 'support' && <SupportView appScriptUrl={appScriptUrl} currentUser={currentUser} showToast={showToast} settings={settings} validationLists={validationLists} />}
                      {activeModule === 'track_requests' && <RequestTrackingView appScriptUrl={appScriptUrl} currentUser={currentUser} showToast={showToast} onRequestNew={() => setIsRequestModalOpen(true)} />}
                      {activeModule === 'registry' && <FleetRegistryView appScriptUrl={appScriptUrl} validationLists={validationLists} onRefresh={() => fetchHistory(true)} showToast={showToast} isLocked={isSystemLocked} />}
                  </div>
              )}
          </main>
          <footer className="mt-auto py-6 border-t border-slate-50 text-center no-print">
              <span className="text-[9px] font-bold text-slate-300 uppercase tracking-[0.2em]">scbc@2026</span>
          </footer>
      </div>

      {isReportModalOpen && selectedReportData && (
          <ReportViewerModal onClose={() => setIsReportModalOpen(false)} onPrint={() => window.print()} title={`Report_${selectedReportData.id || 'History'}`}>
              {activeModule === 'petroleum' ? <PrintablePetroleumReport data={selectedReportData} settings={settings} /> : activeModule === 'petroleum_v2' ? <PrintablePetroleumV2Report data={selectedReportData} settings={settings} /> : activeModule === 'acid' ? <PrintableAcidReport data={selectedReportData} settings={settings} /> : <PrintableGeneralReport data={selectedReportData} settings={settings} />}
          </ReportViewerModal>
      )}
    </div>
  );
};

export default App;

import React from 'react';
import { InspectionStatus } from '../../types';

const StatusButton: React.FC<{label: string, status: InspectionStatus, current: any, onClick: () => void, colorClass: 'green' | 'red' | 'yellow' | 'gray'}> = ({label, status, current, onClick, colorClass}) => {
  const isSelected = status === current;
  const colors = {
    green: isSelected ? 'bg-emerald-600 text-white border-emerald-600 shadow-lg shadow-emerald-100' : 'bg-white text-emerald-700 border-emerald-100 hover:bg-emerald-50',
    red: isSelected ? 'bg-rose-600 text-white border-rose-600 shadow-lg shadow-rose-100' : 'bg-white text-rose-700 border-rose-100 hover:bg-rose-50',
    yellow: isSelected ? 'bg-amber-500 text-white border-amber-500 shadow-lg shadow-amber-100' : 'bg-white text-amber-600 border-amber-100 hover:bg-amber-50',
    gray: isSelected ? 'bg-slate-700 text-white border-slate-700 shadow-lg shadow-slate-100' : 'bg-white text-slate-500 border-slate-200 hover:bg-slate-50',
  };

  return (
    <button 
      onClick={onClick} 
      className={`relative py-2.5 px-0.5 rounded-xl border font-black text-[8px] sm:text-[10px] transition-all flex flex-col items-center justify-center gap-1 flex-1 min-w-0 ${colors[colorClass]} ${isSelected ? 'z-10 scale-[1.02]' : 'shadow-sm opacity-90 hover:opacity-100'}`}
    >
      <div className="h-4 flex items-center justify-center pointer-events-none">
        {status === InspectionStatus.GOOD && <span className="text-sm">✓</span>}
        {status === InspectionStatus.BAD && <span className="text-sm">✕</span>}
        {status === InspectionStatus.ATTENTION && <span className="text-sm">!</span>}
        {status === InspectionStatus.NIL && <span className="text-sm">Ø</span>}
      </div>
      <span className="uppercase tracking-tighter sm:tracking-widest truncate w-full px-0.5 text-center pointer-events-none">
        {label === 'Needs Attention' ? 'Review' : label}
      </span>
    </button>
  );
};

export default StatusButton;

import React, { useState, useEffect } from 'react';
import { InspectionData, InspectionStatus, InspectionItemConfig, ValidationLists, SystemSettings } from '../types';
import { INSPECTION_ITEMS, INSPECTION_CATEGORIES, PETROLEUM_INSPECTION_ITEMS, PETROLEUM_CATEGORIES, ACID_INSPECTION_ITEMS, ACID_CATEGORIES, PETROLEUM_V2_ITEMS, PETROLEUM_V2_CATEGORIES, SECTIONS } from '../constants';
import CameraCapture from '../components/CameraCapture';
import SignaturePad from '../components/SignaturePad';
import StatusButton from '../components/ui/StatusButton';
import Input from '../components/ui/Input';
import AutocompleteInput from '../components/ui/AutocompleteInput';

interface InspectionFormViewProps {
    initialData: InspectionData;
    activeModule: string;
    validationLists: ValidationLists;
    settings: SystemSettings;
    onSaveDraft: (data: InspectionData) => void;
    onSubmit: (data: InspectionData) => void;
    onExit: () => void;
    submissionStatus: 'idle' | 'submitting' | 'success' | 'offline_saved';
    onViewReport: (data: InspectionData) => void;
}

const InspectionFormView: React.FC<InspectionFormViewProps> = ({ 
    initialData, activeModule, validationLists, settings, onSaveDraft, onSubmit, onExit, submissionStatus, onViewReport 
}) => {
    const [formData, setFormData] = useState<InspectionData & any>(initialData);
    const [currentSection, setCurrentSection] = useState(0);
    const [errors, setErrors] = useState<Record<string, boolean>>({});
    const [showDraftSaved, setShowDraftSaved] = useState(false);

    const updateField = (field: string, value: any) => {
        setFormData((prev: any) => ({ ...prev, [field]: value }));
        if (errors[field]) {
            setErrors(prev => {
                const next = {...prev};
                delete next[field];
                return next;
            });
        }
    };

    const handleSaveDraftLocal = () => {
        onSaveDraft(formData);
        setShowDraftSaved(true);
        setTimeout(() => setShowDraftSaved(false), 2000);
    };

    const getItemsForStep = (stepIndex: number): InspectionItemConfig[] => {
        let categories: string[] = [];
        let sourceItems: InspectionItemConfig[] = [];

        if (activeModule === 'general') sourceItems = INSPECTION_ITEMS;
        else if (activeModule === 'petroleum') sourceItems = PETROLEUM_INSPECTION_ITEMS;
        else if (activeModule === 'petroleum_v2') sourceItems = PETROLEUM_V2_ITEMS;
        else if (activeModule === 'acid') sourceItems = ACID_INSPECTION_ITEMS;

        if (activeModule === 'general') {
            if (stepIndex === 2) categories = [INSPECTION_CATEGORIES.PPE, INSPECTION_CATEGORIES.DOCUMENTATION];
            if (stepIndex === 3) categories = [INSPECTION_CATEGORIES.VEHICLE_EXTERIOR, INSPECTION_CATEGORIES.LIGHTS_ELECTRICAL];
            if (stepIndex === 4) categories = [INSPECTION_CATEGORIES.MECHANICAL, INSPECTION_CATEGORIES.TRAILER];
        } else if (activeModule === 'petroleum') {
            if (stepIndex === 2) categories = [PETROLEUM_CATEGORIES.TRUCK_EQUIPMENT];
            if (stepIndex === 3) categories = [PETROLEUM_CATEGORIES.TYRES, PETROLEUM_CATEGORIES.PPE_ID];
            if (stepIndex === 4) categories = [PETROLEUM_CATEGORIES.DOCUMENTS, PETROLEUM_CATEGORIES.ONBOARD];
        } else if (activeModule === 'petroleum_v2') {
            if (stepIndex === 2) categories = [PETROLEUM_V2_CATEGORIES.PRIME_MOVER];
            if (stepIndex === 3) categories = [PETROLEUM_V2_CATEGORIES.TRAILER_TANKS];
            if (stepIndex === 4) categories = [PETROLEUM_V2_CATEGORIES.DRIVER, PETROLEUM_V2_CATEGORIES.SAFETY_SIGNS, PETROLEUM_V2_CATEGORIES.DOCUMENTS];
        } else if (activeModule === 'acid') {
            if (stepIndex === 2) categories = [ACID_CATEGORIES.PPE];
            if (stepIndex === 3) categories = [ACID_CATEGORIES.VEHICLE];
            if (stepIndex === 4) categories = [ACID_CATEGORIES.SPILL_KIT, ACID_CATEGORIES.DOCUMENTATION];
        }

        return sourceItems.filter(item => categories.includes(item.category));
    };

    const validateSection = (sectionIndex: number): boolean => {
        const newErrors: Record<string, boolean> = {};

        if (sectionIndex === 0) {
            if (!formData.truckNo) newErrors.truckNo = true;
            if (!formData.trailerNo) newErrors.trailerNo = true;
            if (!formData.driverName) newErrors.driverName = true;
            if (!formData.location) newErrors.location = true;
            if (!formData.odometer) newErrors.odometer = true;
            if (activeModule !== 'general' && !formData.jobCard) newErrors.jobCard = true;
        }

        if (sectionIndex >= 2 && sectionIndex <= 4) {
            const requiredItems = getItemsForStep(sectionIndex);
            requiredItems.forEach(item => {
                if (!formData[item.id]) newErrors[item.id] = true;
            });
        }

        if (sectionIndex === 5) {
             if (!formData.remarks || formData.remarks.trim() === '') newErrors.remarks = true;
             if (!formData.rate || formData.rate === 0) newErrors.rate = true;
             if (!formData.inspectorSignature) newErrors.inspectorSignature = true;
             if (!formData.driverSignature) newErrors.driverSignature = true;
        }

        if (Object.keys(newErrors).length > 0) {
            setErrors(newErrors);
            window.scrollTo({ top: 0, behavior: 'smooth' }); 
            return false;
        }

        setErrors({});
        return true;
    };

    const validateFullForm = (): boolean => {
        for (let i = 0; i <= 5; i++) {
            if (!validateSection(i)) {
                setCurrentSection(i); 
                return false;
            }
        }
        return true;
    };

    const handleNext = () => {
        if (!validateSection(currentSection)) return;
        window.scrollTo({ top: 0, behavior: 'smooth' });
        setCurrentSection(prev => Math.min(prev + 1, SECTIONS.length - 1));
    };

    const handleBack = () => {
        if (currentSection === 0) {
            onExit();
        } else {
            window.scrollTo({ top: 0, behavior: 'smooth' });
            setCurrentSection(prev => Math.max(prev - 1, 0));
        }
    };

    const handleSubmitInspection = () => {
        if (validateFullForm()) {
            onSubmit(formData);
        }
    };

    const renderDetailsSection = () => (
      <div className="space-y-4 sm:space-y-6 animate-fadeIn">
        {formData.requestId && (
            <div className="bg-gradient-to-r from-indigo-600 to-indigo-800 p-4 sm:p-5 rounded-2xl shadow-xl flex items-center justify-between text-white border border-indigo-400/30">
                <div className="flex items-center gap-3 sm:gap-4">
                    <div className="p-2 bg-white/10 rounded-xl backdrop-blur-md">
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-3 7h3m-3 4h3m-6-4h.01M9 16h.01"></path></svg>
                    </div>
                    <div>
                        <p className="text-[9px] sm:text-[10px] font-black uppercase tracking-widest text-indigo-200">Active Mission</p>
                        <p className="text-sm sm:text-base font-black tracking-tight uppercase">Request ID: {formData.requestId}</p>
                    </div>
                </div>
            </div>
        )}

        <div className="bg-white p-5 sm:p-8 rounded-3xl shadow-sm border border-slate-100">
          <h2 className="text-xl sm:text-2xl font-black text-slate-800 mb-6 sm:mb-8 uppercase tracking-tight">Vehicle Identity</h2>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-y-6 sm:gap-y-8 gap-x-10">
            <AutocompleteInput label="Truck Reg No *" value={formData.truckNo} onChange={v => updateField('truckNo', v)} options={validationLists.trucks} placeholder="e.g. ABC 123" isRegNo={true} error={errors.truckNo} />
            <AutocompleteInput label="Trailer No *" value={formData.trailerNo} onChange={v => updateField('trailerNo', v)} options={validationLists.trailers} placeholder="e.g. T-100" isRegNo={true} error={errors.trailerNo} />
            <Input label="Job Card Reference" value={formData.jobCard || ''} onChange={v => updateField('jobCard', v)} error={errors.jobCard} />
            <AutocompleteInput label="Primary Inspector" value={formData.inspectedBy} onChange={v => updateField('inspectedBy', v)} options={validationLists.inspectors} isTitleCase={true} readOnly={true} />
            <AutocompleteInput label="Driver Name *" value={formData.driverName} onChange={v => updateField('driverName', v)} options={validationLists.drivers} placeholder="Verified Identity" isTitleCase={true} error={errors.driverName} />
            <AutocompleteInput label="Station Location *" value={formData.location} onChange={v => updateField('location', v)} options={validationLists.locations} placeholder="Hub" isTitleCase={true} error={errors.location} />
            <Input label="Odometer Readout (km) *" type="number" value={formData.odometer} onChange={v => updateField('odometer', v)} error={errors.odometer} />
          </div>
        </div>
      </div>
    );

    const renderPhotosSection = () => (
      <div className="space-y-4 sm:space-y-6 animate-fadeIn">
         <div className="bg-white p-5 sm:p-8 rounded-3xl shadow-sm border border-slate-100">
          <h2 className="text-xl sm:text-2xl font-black text-slate-800 mb-6 sm:mb-8 uppercase tracking-tight">Visual Documentation</h2>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 sm:gap-6">
            <CameraCapture label="Horse: Front" existingImage={formData.photoFront} onCapture={img => updateField('photoFront', img)} />
            <CameraCapture label="Horse: Left Profile" existingImage={formData.photoLS} onCapture={img => updateField('photoLS', img)} />
            <CameraCapture label="Horse: Right Profile" existingImage={formData.photoRS} onCapture={img => updateField('photoRS', img)} />
            <CameraCapture label="Trailer: Rear Aspect" existingImage={formData.photoBack} onCapture={img => updateField('photoBack', img)} />
          </div>
        </div>
      </div>
    );

    const renderInspectionSection = (categoriesToShow: string[]) => {
        const itemsToRender = getItemsForStep(currentSection).filter(i => categoriesToShow.includes(i.category));
        const grouping: Record<string, InspectionItemConfig[]> = {};
        categoriesToShow.forEach(cat => {
            grouping[cat] = itemsToRender.filter(i => i.category === cat);
        });

        return (
          <div className="space-y-6 sm:space-y-10 animate-fadeIn">
            {categoriesToShow.map(cat => (
              <div key={cat} className="bg-white rounded-[1.5rem] sm:rounded-[2rem] shadow-sm border border-slate-100 overflow-hidden">
                <div className="bg-slate-50 px-5 sm:px-8 py-4 border-b border-slate-100 flex justify-between items-center">
                  <h3 className="text-[9px] sm:text-[11px] font-black text-slate-500 uppercase tracking-[0.2em]">{cat}</h3>
                  <span className="text-[7px] sm:text-[8px] font-black bg-rose-50 text-rose-500 px-2 py-1 rounded uppercase tracking-widest border border-rose-100">Verification Req.</span>
                </div>
                <div className="divide-y divide-slate-50">
                  {grouping[cat].map(item => (
                    <div key={item.id} className={`p-5 sm:p-8 transition-colors ${errors[item.id] ? 'bg-rose-50/40' : 'hover:bg-slate-50/30'}`}>
                      <div className="mb-4 sm:mb-5">
                          <span className={`font-bold text-xs sm:text-sm leading-tight uppercase tracking-tight ${errors[item.id] ? 'text-rose-800' : 'text-slate-700'}`}>
