interface LauncherTileProps {
    id: string;
    label: string;
    icon: React.ReactNode;
    isForcedLock?: boolean;
    badgeCount?: number;
    badgeColor?: string;
    isInspectionModule?: boolean;
    isLocked: boolean;
    isPro?: boolean;
    isEnterprise?: boolean;
    onNavigate: (module: string) => void;
}

const LauncherTile = ({ 
    id, label, icon, isForcedLock = false, badgeCount = 0, badgeColor = 'bg-slate-900', 
    isInspectionModule = false, isLocked, isPro = false, isEnterprise = false, onNavigate
}: LauncherTileProps) => {
    const effectiveLock = isForcedLock || (isInspectionModule && isLocked);
    return (
        <button 
            onClick={() => !effectiveLock && onNavigate(id)}
            className={`flex flex-col items-center justify-center p-2 sm:p-4 transition-all w-full group ${effectiveLock ? 'opacity-25 cursor-not-allowed' : 'hover:opacity-60 active:scale-95'}`}
        >
            <div className="relative mb-2 sm:mb-5">
                {icon}
                {effectiveLock && (
